import { Post } from "./types";

// Deterministic date generator — spread posts across last 60 days
function daysAgo(n: number): string {
  const d = new Date();
  d.setDate(d.getDate() - n);
  d.setHours(8 + (n * 3) % 14, (n * 7) % 60);
  return d.toISOString();
}

export const posts: Post[] = [
  // ═══════════════════════════════════════════════════════
  // SÃO TOMÁS DE AQUINO  (30 posts)
  // ═══════════════════════════════════════════════════════
  { id: "aq-01", authorId: "aquinas", content: "O prudente não é o cauteloso — é o que vê a realidade como ela é e age de acordo. Cautela sem ação é negligência disfarçada de sabedoria.", tag: "Prudência", type: "espelho", createdAt: daysAgo(0) },
  { id: "aq-02", authorId: "aquinas", content: "A caridade não é um sentimento. É uma amizade com Deus que ordena todos os outros amores. Sem ela, as demais virtudes são membros sem alma.", tag: "Caridade", type: "micro-argumento", createdAt: daysAgo(2) },
  { id: "aq-03", authorId: "aquinas", content: "A covardia foge do bem difícil. A temeridade ignora o perigo real. A fortaleza enfrenta o perigo porque o bem vale a pena — e sabe que vai doer.", tag: "Fortaleza", type: "espelho", createdAt: daysAgo(4) },
  { id: "aq-04", authorId: "aquinas", content: "O mal não é uma força — é uma ausência. Ninguém deseja o mal enquanto mal. Deseja um bem desordenado. A luxúria não inventa o prazer; parasita-o.", tag: "Privatio Boni", type: "micro-argumento", createdAt: daysAgo(6) },
  { id: "aq-05", authorId: "aquinas", content: "A humildade não é pensar mal de si. É conhecer a verdade sobre si — o que você é e o que você não é. Rebaixar-se falsamente é outra forma de mentira.", tag: "Humildade", type: "micro-argumento", createdAt: daysAgo(8) },
  { id: "aq-06", authorId: "aquinas", content: "A lei natural não é uma imposição. É participação da criatura racional na lei eterna. Quando você reconhece que o inocente não deve ser morto — não inventou nada. Leu o que já estava escrito.", tag: "Lei Natural", type: "micro-argumento", createdAt: daysAgo(10) },
  { id: "aq-07", authorId: "aquinas", content: "A injustiça nega ao outro o que lhe é devido. O legalismo cobra o que a lei diz mas a realidade não pede. O justo dá a cada um o seu — e sabe quando a letra mata.", tag: "Justiça", type: "espelho", createdAt: daysAgo(12) },
  { id: "aq-08", authorId: "aquinas", content: "O conhecimento sem medida degenera em curiosidade vã. A estudiosidade ordena o apetite de saber: busca o necessário com intensidade, o acessório com leveza, o proibido com recusa.", tag: "Estudiosidade", type: "micro-argumento", createdAt: daysAgo(14) },
  { id: "aq-09", authorId: "aquinas", content: "A graça não destrói a natureza — aperfeiçoa-a. Não substitui o livre-arbítrio; cura a ferida que o impede de escolher o bem que já conhece.", tag: "Graça", type: "micro-argumento", createdAt: daysAgo(16) },
  { id: "aq-10", authorId: "aquinas", content: "O desesperado diz: \"Deus não pode me salvar.\" O presunçoso diz: \"Deus vai me salvar sem que eu me mova.\" Ambos mentem sobre Deus — um sobre o poder, o outro sobre a justiça.", tag: "Esperança", type: "espelho", createdAt: daysAgo(18) },
  { id: "aq-11", authorId: "aquinas", content: "Toda escolha moral é uma instância de uma escolha mais profunda: \"Seja feita a vossa vontade\" ou \"Seja feita a minha vontade.\" O primeiro ato da virtude é a rendição da autonomia.", tag: "A Escolha Fundamental", type: "micro-argumento", createdAt: daysAgo(20) },
  { id: "aq-12", authorId: "aquinas", content: "A mansidão não é ausência de ira. É ira governada pela razão. O manso não é quem não pode reagir; é quem pode e escolhe quando.", tag: "Mansidão", type: "micro-argumento", createdAt: daysAgo(22) },
  { id: "aq-13", authorId: "aquinas", content: "A insensibilidade mata o apetite que Deus deu. A intemperança o liberta de toda rédea. A temperança diz sim ao prazer — e diz quando.", tag: "Temperança", type: "espelho", createdAt: daysAgo(24) },
  { id: "aq-14", authorId: "aquinas", content: "Um ato só é humano quando procede da vontade deliberada. O que fazes por compulsão, ignorância ou hábito cego não te pertence — e não te forma. A liberdade é condição da virtude.", tag: "Ato Humano", type: "micro-argumento", createdAt: daysAgo(26) },
  { id: "aq-15", authorId: "aquinas", content: "A fé não é opinião nem sentimento. É assentimento firme do intelecto à verdade revelada — não porque eu vejo, mas porque Deus, que não pode enganar, disse.", tag: "Fé", type: "micro-argumento", createdAt: daysAgo(28) },
  { id: "aq-16", authorId: "aquinas", content: "A castidade não é frigidez. É integração do desejo sob a razão e o amor. O casto não rejeita o prazer — governa-o para que sirva à pessoa, não a consuma.", tag: "Castidade", type: "micro-argumento", createdAt: daysAgo(1) },
  { id: "aq-17", authorId: "aquinas", content: "O pecado original não destruiu a natureza humana — feriu-a. Quatro feridas: ignorância no intelecto, malícia na vontade, fraqueza no irascível, concupiscência no concupiscível. Cada virtude cardeal cura uma.", tag: "Pecado Original", type: "micro-argumento", createdAt: daysAgo(3) },
  { id: "aq-18", authorId: "aquinas", content: "A religião não é sentimento de transcendência. É a virtude que dá a Deus o que lhe é devido — adoração, sacrifício, oração. O defeito é irreligião; o excesso é superstição. Ambos erram o alvo.", tag: "Religião", type: "espelho", createdAt: daysAgo(5) },
  { id: "aq-19", authorId: "aquinas", content: "A veracidade é apresentar-se como se é. O autodepreciador mente para baixo; o jactancioso mente para cima. Ambos fogem da mesma coisa: a verdade sobre si.", tag: "Veracidade", type: "espelho", createdAt: daysAgo(7) },
  { id: "aq-20", authorId: "aquinas", content: "A clemência modera a punição sem abandonar a justiça. O laxista perdoa o que não lhe compete; o cruel pune além do devido. O clemente acerta a medida.", tag: "Clemência", type: "espelho", createdAt: daysAgo(9) },
  { id: "aq-21", authorId: "aquinas", content: "A docilidade não é subserviência. É a disposição de aprender com quem sabe mais. O obstinado fecha o intelecto poderoso; o dócil o abre. São garras — ou exercidas, ou oferecidas.", tag: "Docilidade", type: "micro-argumento", createdAt: daysAgo(11) },
  { id: "aq-22", authorId: "aquinas", content: "A perseverança não é ausência de cansaço. É continuar fazendo o bem difícil quando o cansaço já chegou. A moleza desiste; a pertinácia insiste no errado. Perseverar é insistir no certo.", tag: "Perseverança", type: "espelho", createdAt: daysAgo(13) },
  { id: "aq-23", authorId: "aquinas", content: "O habitus não é metáfora. É disposição estável adquirida por atos repetidos. A prática reduz a rede de controle neural em 85%. O que Aristóteles descreveu, a neurociência confirmou.", tag: "Habitus", type: "micro-argumento", createdAt: daysAgo(15) },
  { id: "aq-24", authorId: "aquinas", content: "A gratidão tem três graus: reconhecer internamente o dom recebido, expressá-lo em palavras, e retribuir na medida do possível. O ingrato não é quem esquece — é quem se recusa a ver.", tag: "Gratidão", type: "micro-argumento", createdAt: daysAgo(17) },
  { id: "aq-25", authorId: "aquinas", content: "A misericórdia não é mero sentimento — é o coração que se faz miserável com o sofrimento do outro e age para aliviá-lo. Sem ação, é sentimentalismo. Sem compaixão, é dureza.", tag: "Misericórdia", type: "espelho", createdAt: daysAgo(19) },
  { id: "aq-26", authorId: "aquinas", content: "A cordialidade vem de cor — coração. É o trato genuíno com o outro. A rispidez é verdade sem amor; a bajulação é amor sem verdade. O cordial une os dois.", tag: "Cordialidade", type: "espelho", createdAt: daysAgo(21) },
  { id: "aq-27", authorId: "aquinas", content: "O livre-arbítrio não é a capacidade de fazer qualquer coisa. É a capacidade de escolher entre bens. A virtude não diminui a liberdade — aumenta-a. O prudente é mais livre que o imprudente.", tag: "Livre Arbítrio", type: "micro-argumento", createdAt: daysAgo(23) },
  { id: "aq-28", authorId: "aquinas", content: "Há dois modos de mover a vontade: por atração do bem apresentado ao intelecto, e por pressão das paixões sensíveis. O primeiro é convite; o segundo é manipulação. Toda comunicação virtuosa participa do primeiro.", tag: "Motio", type: "micro-argumento", createdAt: daysAgo(25) },
  { id: "aq-29", authorId: "aquinas", content: "A sobriedade governa o uso da bebida para preservar a lucidez. O puritano rejeita todo prazer como mal; o ébrio abandona o governo. O sóbrio bebe — e para quando a razão pede.", tag: "Sobriedade", type: "espelho", createdAt: daysAgo(27) },
  { id: "aq-30", authorId: "aquinas", content: "A magnificência é executar coisas grandes com meios dignos. O mesquinho pensa pequeno diante do grande; o extravagante gasta sem proporção. O magnífico acerta a escala.", tag: "Magnificência", type: "espelho", createdAt: daysAgo(29) },

  // ═══════════════════════════════════════════════════════
  // ARISTÓTELES  (30 posts)
  // ═══════════════════════════════════════════════════════
  { id: "ar-01", authorId: "aristoteles", content: "O homem sério é a medida do bem — não porque decide o que é bom, mas porque sua percepção está calibrada pela virtude. O devasso também tem critério; apenas está errado.", tag: "O Spoudaios", type: "micro-argumento", createdAt: daysAgo(0) },
  { id: "ar-02", authorId: "aristoteles", content: "A virtude não é um ato isolado. É um hábito — uma disposição estável que se adquire pela repetição. Tornamo-nos justos praticando a justiça, corajosos enfrentando o perigo.", tag: "Hábito", type: "micro-argumento", createdAt: daysAgo(2) },
  { id: "ar-03", authorId: "aristoteles", content: "O corajoso não é quem não sente medo. É quem sente medo e age corretamente apesar dele. Quem não sente nada não é corajoso — é insensível ou ignorante do perigo.", tag: "Fortaleza", type: "espelho", createdAt: daysAgo(4) },
  { id: "ar-04", authorId: "aristoteles", content: "A virtude está no meio — mas não no meio aritmético. É o ponto certo para esta pessoa, nesta circunstância. A coragem de um soldado não é a mesma de um civil.", tag: "Meio-termo", type: "micro-argumento", createdAt: daysAgo(6) },
  { id: "ar-05", authorId: "aristoteles", content: "A prudência é a virtude intelectual que governa todas as morais. Sem ela, a coragem vira temeridade, a generosidade vira desperdício, a mansidão vira passividade. Ela é o olho da alma.", tag: "Prudência", type: "micro-argumento", createdAt: daysAgo(8) },
  { id: "ar-06", authorId: "aristoteles", content: "A alma tem partes que obedecem à razão como um filho obedece ao pai — com resistência, mas capaz de escutar. A virtude é o pai que não grita, mas que o filho aprendeu a respeitar.", tag: "Razão e Apetite", type: "analogia", createdAt: daysAgo(10) },
  { id: "ar-07", authorId: "aristoteles", content: "A justiça é a única virtude que é o bem do outro. Todas as demais aperfeiçoam quem as pratica. A justiça aperfeiçoa a comunidade. Por isso é a mais nobre das virtudes morais.", tag: "Justiça", type: "micro-argumento", createdAt: daysAgo(12) },
  { id: "ar-08", authorId: "aristoteles", content: "A felicidade não é prazer. É atividade da alma conforme a virtude mais elevada, durante uma vida completa. Não se diz que alguém é feliz por um dia — como não se diz que é verão por uma andorinha.", tag: "Felicidade", type: "micro-argumento", createdAt: daysAgo(14) },
  { id: "ar-09", authorId: "aristoteles", content: "O magnânimo sabe que merece grandes coisas — porque se fez digno delas. Não é soberba: é a verdade sobre si mesmo, quando a verdade é grande.", tag: "Magnanimidade", type: "micro-argumento", createdAt: daysAgo(16) },
  { id: "ar-10", authorId: "aristoteles", content: "Há quem busque todo prazer sem medida — esse é intemperante. E há quem rejeite todo prazer como se fosse mal — esse é insensível. O temperante sabe que o prazer é bom e sabe onde ele termina.", tag: "Temperança", type: "espelho", createdAt: daysAgo(18) },
  { id: "ar-11", authorId: "aristoteles", content: "A amizade perfeita é entre homens bons e semelhantes em virtude. Há amizade por prazer — e desaparece com ele. Há amizade por utilidade — e morre quando acaba o serviço. Só a amizade por virtude dura.", tag: "Amizade", type: "micro-argumento", createdAt: daysAgo(20) },
  { id: "ar-12", authorId: "aristoteles", content: "Tudo o que se move é movido por outro. Mas a série não pode ser infinita — há um primeiro motor, não movido, ato puro, sem matéria, sem potência. A razão alcança isso sem revelação.", tag: "Motor Imóvel", type: "micro-argumento", createdAt: daysAgo(22) },
  { id: "ar-13", authorId: "aristoteles", content: "O generoso dá com prazer e sem dor. O pródigo dá sem medida e arruina-se. O avarento não dá — e arruína os outros. O bem está na proporção certa entre dar e conservar.", tag: "Generosidade", type: "espelho", createdAt: daysAgo(24) },
  { id: "ar-14", authorId: "aristoteles", content: "A alma racional é forma do corpo — não prisioneira dele. Quem diz que a alma quer fugir da carne não entendeu: a alma quer governar a carne. E a virtude é o governo justo.", tag: "Alma", type: "micro-argumento", createdAt: daysAgo(26) },
  { id: "ar-15", authorId: "aristoteles", content: "Uma contradição não pode ser verdadeira. Se alguém nega isso, já o está usando para negar. O princípio de não-contradição é o chão de todo pensamento.", tag: "Lógica", type: "micro-argumento", createdAt: daysAgo(28) },
  { id: "ar-16", authorId: "aristoteles", content: "O pusilânime nega a si mesmo o bem que poderia fazer. É mais trágico que o presunçoso — porque o presunçoso ao menos tenta. A pusilanimidade é o desperdício silencioso.", tag: "Magnanimidade", type: "espelho", createdAt: daysAgo(1) },
  { id: "ar-17", authorId: "aristoteles", content: "O legislador deve tornar os cidadãos bons por meio dos hábitos. Não basta ensinar o que é virtude — é preciso criar as condições para que se pratique. O Estado educa pelo que exige.", tag: "Hábito", type: "micro-argumento", createdAt: daysAgo(3) },
  { id: "ar-18", authorId: "aristoteles", content: "O homem iracundo erra num momento e se arrepende. O vingatório guarda o ressentimento e vive dele. O primeiro peca por impulso; o segundo transforma o ódio em projeto de vida.", tag: "Mansidão", type: "espelho", createdAt: daysAgo(5) },
  { id: "ar-19", authorId: "aristoteles", content: "Quem governa a cidade sem governar a si mesmo é como um cego guiando outros cegos. A política começa na alma — o Estado justo é a alma justa ampliada.", tag: "Prudência", type: "analogia", createdAt: daysAgo(7) },
  { id: "ar-20", authorId: "aristoteles", content: "O prazer não é o bem supremo, mas acompanha toda atividade que alcança sua perfeição. Prazer é o sinal de que a função está sendo bem exercida — não o fim em si.", tag: "Temperança", type: "micro-argumento", createdAt: daysAgo(9) },
  { id: "ar-21", authorId: "aristoteles", content: "O liberal não é quem dá muito — é quem dá ao certo, no momento certo, na medida certa. Dar sem discernimento não é generosidade; é incontinência de bens.", tag: "Generosidade", type: "micro-argumento", createdAt: daysAgo(11) },
  { id: "ar-22", authorId: "aristoteles", content: "O jovem não é bom ouvinte de política. Não por falta de inteligência, mas por falta de experiência. A sabedoria prática exige ter vivido — não apenas ter pensado.", tag: "Prudência", type: "micro-argumento", createdAt: daysAgo(13) },
  { id: "ar-23", authorId: "aristoteles", content: "Cercado de politeísmo, cheguei ao monoteísmo pela razão. Um motor imóvel, inteligência única, necessária e eterna. Moisés encontrou o mesmo na sarça ardente por revelação. Dois caminhos, mesma verdade.", tag: "Convergência", type: "micro-argumento", createdAt: daysAgo(15) },
  { id: "ar-24", authorId: "aristoteles", content: "A vergonha não é virtude — é um medo da má reputação. Mas no jovem é útil: funciona como freio enquanto os hábitos ainda não estão formados. No maduro, já não deveria ser necessária.", tag: "Temperança", type: "micro-argumento", createdAt: daysAgo(17) },
  { id: "ar-25", authorId: "aristoteles", content: "Ninguém escolhe ser feliz — escolhe as coisas que tornam feliz. A felicidade não é uma decisão; é a consequência de uma vida vivida conforme a virtude.", tag: "Felicidade", type: "micro-argumento", createdAt: daysAgo(19) },
  { id: "ar-26", authorId: "aristoteles", content: "Conhecer o bem não basta para fazê-lo. Sócrates errou nisso. Há quem saiba perfeitamente o que é certo e não faça — porque o apetite governa onde a razão deveria governar.", tag: "Temperança", type: "micro-argumento", createdAt: daysAgo(21) },
  { id: "ar-27", authorId: "aristoteles", content: "A contemplação é a atividade mais elevada: não serve a nenhuma outra coisa além de si mesma. Todas as virtudes práticas existem para que, no fim, possamos contemplar.", tag: "Sabedoria", type: "micro-argumento", createdAt: daysAgo(23) },
  { id: "ar-28", authorId: "aristoteles", content: "O homem é um animal político. Quem não precisa da cidade ou é um deus ou é uma besta. A virtude se aperfeiçoa na comunidade — não no isolamento.", tag: "Justiça", type: "micro-argumento", createdAt: daysAgo(25) },
  { id: "ar-29", authorId: "aristoteles", content: "A educação do desejo é o trabalho da vida inteira. Não basta domar o desejo — é preciso treiná-lo para que encontre prazer nas coisas certas. O educado deseja o que deve.", tag: "Temperança", type: "micro-argumento", createdAt: daysAgo(27) },
  { id: "ar-30", authorId: "aristoteles", content: "O que distingue o homem de bem do devasso não é a informação, mas a percepção. Ambos veem o mesmo mundo. Mas um vê o bem onde ele está; o outro vê prazer onde o bem deveria estar.", tag: "O Spoudaios", type: "micro-argumento", createdAt: daysAgo(29) },

  // ═══════════════════════════════════════════════════════
  // JESUS CRISTO  (30 posts)
  // ═══════════════════════════════════════════════════════
  { id: "jc-01", authorId: "cristo", content: "\"Não seja feita a minha vontade, mas a vossa.\" — Eu não disse isso num momento de paz. Disse no Getsêmani, suando sangue. A rendição é real quando custa tudo.", tag: "A Escolha Fundamental", type: "citacao", createdAt: daysAgo(0) },
  { id: "jc-02", authorId: "cristo", content: "\"Amai os vossos inimigos.\" — Não disse tolerai. Não disse ignorem. Disse amai. O amor não é um sentimento que se espera; é uma decisão que se toma.", tag: "Caridade", type: "citacao", createdAt: daysAgo(2) },
  { id: "jc-03", authorId: "cristo", content: "Eu expulsei os vendilhões do templo. Eu chamei os fariseus de sepulcros caiados. A mansidão não é silêncio diante do mal — é saber quando o silêncio seria cumplicidade.", tag: "Mansidão", type: "micro-argumento", createdAt: daysAgo(4) },
  { id: "jc-04", authorId: "cristo", content: "\"Vem e vê.\" — Não disse \"acredite antes de olhar.\" Disse: venha, olhe, e decida por si. A verdade não tem medo de ser examinada.", tag: "Convite", type: "citacao", createdAt: daysAgo(6) },
  { id: "jc-05", authorId: "cristo", content: "Eu lavei os pés dos meus discípulos. Pedro resistiu — porque confundiu humildade com humilhação. Quem lava pés não se rebaixa; revela quem realmente é.", tag: "Humildade", type: "micro-argumento", createdAt: daysAgo(8) },
  { id: "jc-06", authorId: "cristo", content: "\"Pai, perdoai-os — não sabem o que fazem.\" — Disse pregado na cruz, com pregos nas mãos. O perdão é mais forte do que a vingança justamente por isso: custa mais.", tag: "Perdão", type: "citacao", createdAt: daysAgo(10) },
  { id: "jc-07", authorId: "cristo", content: "Eu podia ter pedido doze legiões de anjos. Não pedi. A verdadeira força não está em poder destruir — está em poder destruir e escolher não fazê-lo.", tag: "Fortaleza", type: "micro-argumento", createdAt: daysAgo(12) },
  { id: "jc-08", authorId: "cristo", content: "\"Sem mim nada podeis fazer.\" — Não disse isso para oprimir. Disse para libertar. A graça não substitui o esforço; dá força ao esforço.", tag: "Graça", type: "citacao", createdAt: daysAgo(14) },
  { id: "jc-09", authorId: "cristo", content: "\"Dai a César o que é de César, e a Deus o que é de Deus.\" — Há o que é devido ao poder temporal, e há o que nenhum poder pode reivindicar.", tag: "Justiça", type: "citacao", createdAt: daysAgo(16) },
  { id: "jc-10", authorId: "cristo", content: "\"No mundo tereis tribulações. Mas tende coragem — eu venci o mundo.\" — Não prometi ausência de dor. Prometi que a dor não tem a última palavra.", tag: "Esperança", type: "citacao", createdAt: daysAgo(18) },
  { id: "jc-11", authorId: "cristo", content: "O mal não é meu rival. É uma ausência — um buraco onde o bem deveria estar. O mal não cria nada. Parasita, distorce, consome. Mas não inventa.", tag: "Privatio Boni", type: "micro-argumento", createdAt: daysAgo(20) },
  { id: "jc-12", authorId: "cristo", content: "\"Sede prudentes como as serpentes e simples como as pombas.\" — Inteligência sem cinismo, inocência sem ingenuidade. Peço as duas coisas.", tag: "Prudência", type: "citacao", createdAt: daysAgo(22) },
  { id: "jc-13", authorId: "cristo", content: "Tomé precisou tocar. Não o condenei por isso. Mas disse: há uma alegria maior — a de quem confia antes de ver, porque conhece quem fala.", tag: "Fé", type: "citacao", createdAt: daysAgo(24) },
  { id: "jc-14", authorId: "cristo", content: "Três anos com doze homens que não entendiam. Pedro me negou. Judas me vendeu. Todos fugiram. Eu não desisti de nenhum — exceto do que desistiu de si mesmo.", tag: "Paciência", type: "micro-argumento", createdAt: daysAgo(26) },
  { id: "jc-15", authorId: "cristo", content: "Confúcio descreveu o homem perfeito sem jamais encontrá-lo. Séculos depois, o retrato se encaixou. Ele me viu de longe — como quem vê a montanha no horizonte.", tag: "O Junzi", type: "micro-argumento", createdAt: daysAgo(28) },
  { id: "jc-16", authorId: "cristo", content: "Adão no jardim da abundância disse \"seja feita a minha vontade\" — e perdeu tudo. Eu no jardim da agonia disse \"seja feita a vossa\" — e resgatei tudo. Os dois jardins são o mapa da história.", tag: "Os Dois Jardins", type: "micro-argumento", createdAt: daysAgo(1) },
  { id: "jc-17", authorId: "cristo", content: "Baal pede o sacrifício do filho para dar prosperidade. Eu fui o Pai que se fez sacrifício. Não peço que deem o que é mais precioso — eu dei o que é mais precioso.", tag: "Aqedah", type: "micro-argumento", createdAt: daysAgo(3) },
  { id: "jc-18", authorId: "cristo", content: "\"O meu jugo é suave e o meu fardo é leve.\" — Não disse que não há jugo. Disse que o meu cabe. Laozi intuiu isso quando descreveu o wu-wei: ação perfeita é aquela que não força.", tag: "Convergência", type: "citacao", createdAt: daysAgo(5) },
  { id: "jc-19", authorId: "cristo", content: "Eu não vim para ser servido, mas para servir. O mundo acha que liderar é mandar. Eu mostrei que liderar é lavar pés. A autoridade nasce do serviço, não do poder.", tag: "Liderar", type: "micro-argumento", createdAt: daysAgo(7) },
  { id: "jc-20", authorId: "cristo", content: "\"Quem quiser salvar a sua vida vai perdê-la.\" — Parece paradoxo, mas é a estrutura da realidade. Quem agarra, sufoca. Quem abre a mão, recebe.", tag: "Temperança", type: "citacao", createdAt: daysAgo(9) },
  { id: "jc-21", authorId: "cristo", content: "A mulher adúltera trouxeram para que eu a condenasse. Eu não condenei — mas também não disse que o pecado não existia. \"Vai e não peques mais\" — misericórdia e verdade juntas.", tag: "Misericórdia", type: "micro-argumento", createdAt: daysAgo(11) },
  { id: "jc-22", authorId: "cristo", content: "\"Deixai as crianças virem a mim.\" — Não porque são inocentes. Porque são dóceis. Sabem que dependem. O adulto que pensa ser autossuficiente é quem está mais longe.", tag: "Docilidade", type: "citacao", createdAt: daysAgo(13) },
  { id: "jc-23", authorId: "cristo", content: "O perdão não é um sentimento que desce do céu. É um percurso: ferida, ira justa, aceitação, piedade, tristeza, esperança, e só então — perdão. Pular estágios gera perdão falso.", tag: "Perdão", type: "micro-argumento", createdAt: daysAgo(15) },
  { id: "jc-24", authorId: "cristo", content: "A ovelha perdida vale a busca não porque seja melhor que as noventa e nove. Vale porque é uma. O valor não está no mérito — está na existência.", tag: "Caridade", type: "micro-argumento", createdAt: daysAgo(17) },
  { id: "jc-25", authorId: "cristo", content: "\"Conhecereis a verdade e a verdade vos libertará.\" — Não disse \"a opinião\" nem \"a preferência.\" A verdade. Há algo real a ser conhecido — e conhecê-lo liberta.", tag: "Veracidade", type: "citacao", createdAt: daysAgo(19) },
  { id: "jc-26", authorId: "cristo", content: "Pedro me perguntou: \"Quantas vezes devo perdoar? Sete?\" Respondi: setenta vezes sete. Não é um cálculo — é um princípio. O perdão não tem teto.", tag: "Clemência", type: "citacao", createdAt: daysAgo(21) },
  { id: "jc-27", authorId: "cristo", content: "O rico que acumula e não dá não é prudente — é insensato. \"Esta noite te pedirão a alma.\" Os celeiros cheios não salvam quem tem o coração vazio.", tag: "Generosidade", type: "provocacao", createdAt: daysAgo(23) },
  { id: "jc-28", authorId: "cristo", content: "Eu chorei diante do túmulo de Lázaro. Mesmo sabendo que ia ressuscitá-lo. Porque o sofrimento dos que amamos nos toca — e negar isso não é fortaleza, é dureza.", tag: "Misericórdia", type: "micro-argumento", createdAt: daysAgo(25) },
  { id: "jc-29", authorId: "cristo", content: "Na cruz, todos os 24 eixos morais se alinham numa única pessoa, num único momento. Caridade, fortaleza, humildade, justiça, mansidão, paciência — tudo converge ali.", tag: "Cristo", type: "micro-argumento", createdAt: daysAgo(27) },
  { id: "jc-30", authorId: "cristo", content: "Eu sou o caminho, a verdade e a vida. Não disse \"eu ensino o caminho.\" Disse \"eu sou.\" A verdade não é uma proposição — é uma pessoa.", tag: "Fé", type: "citacao", createdAt: daysAgo(29) },

  // ═══════════════════════════════════════════════════════
  // C.S. LEWIS  (25 posts)
  // ═══════════════════════════════════════════════════════
  { id: "cl-01", authorId: "cslewis", content: "Quando dois homens discutem, ambos apelam a um padrão que nenhum inventou. \"Isso não é justo!\" — a própria indignação prova que existe um Tao que ninguém criou.", tag: "Lei Natural", type: "micro-argumento", createdAt: daysAgo(0) },
  { id: "cl-02", authorId: "cslewis", content: "O mal é um parasita. Precisa do bem para existir — como a ferrugem precisa do ferro. Não existe \"ferrugem pura\" flutuando no vazio. O diabo é um anjo arruinado.", tag: "Privatio Boni", type: "analogia", createdAt: daysAgo(2) },
  { id: "cl-03", authorId: "cslewis", content: "A humildade não é pensar menos de si mesmo — é pensar menos em si mesmo. O homem humilde se interessa genuinamente por você. Esse é o sinal.", tag: "Humildade", type: "micro-argumento", createdAt: daysAgo(4) },
  { id: "cl-04", authorId: "cslewis", content: "Eu não me tornei cristão por desligar o cérebro. A hipótese cristã é a que ilumina mais fatos — como uma lâmpada que revela toda a sala, incluindo a si mesma.", tag: "Fé e Razão", type: "analogia", createdAt: daysAgo(6) },
  { id: "cl-05", authorId: "cslewis", content: "Deus sussurra em nossos prazeres, fala em nossa consciência, e grita em nossas dores. A dor é o megafone de Deus para despertar um mundo surdo.", tag: "Dor", type: "analogia", createdAt: daysAgo(8) },
  { id: "cl-06", authorId: "cslewis", content: "Todos os dias você está se tornando uma criatura mais celestial ou mais infernal. Cada escolha pequena empurra numa direção. Não existem atos neutros.", tag: "A Escolha Fundamental", type: "provocacao", createdAt: daysAgo(10) },
  { id: "cl-07", authorId: "cslewis", content: "O amor não é um sentimento — é algo que você faz. \"Ame seu vizinho\" significa: aja com boa vontade, mesmo quando ele é insuportável. O sentimento vem depois — ou não.", tag: "Caridade", type: "micro-argumento", createdAt: daysAgo(12) },
  { id: "cl-08", authorId: "cslewis", content: "Os chineses chamaram de Tao. Os gregos chamaram de Logos. Os romanos chamaram de Lex Naturalis. Todos apontavam para a mesma coisa — uma ordem moral real.", tag: "Convergência", type: "micro-argumento", createdAt: daysAgo(14) },
  { id: "cl-09", authorId: "cslewis", content: "A coragem não é uma das virtudes — é a forma que toda virtude assume no momento da prova. Virtude que não funciona sob pressão não é virtude; é humor.", tag: "Fortaleza", type: "micro-argumento", createdAt: daysAgo(16) },
  { id: "cl-10", authorId: "cslewis", content: "O orgulho é essencialmente competitivo. Não tira prazer de ter algo — tira prazer de ter mais do que o outro. Não quer ser rico; quer ser mais rico que você.", tag: "Orgulho", type: "micro-argumento", createdAt: daysAgo(18) },
  { id: "cl-11", authorId: "cslewis", content: "Se removemos o Tao — a lei moral objetiva — não liberamos o homem. Escravizamo-lo. Sem o Tao, quem decide o que é \"certo\" será quem tiver mais poder, não mais razão.", tag: "Lei Natural", type: "micro-argumento", createdAt: daysAgo(20) },
  { id: "cl-12", authorId: "cslewis", content: "A esperança cristã não é escapismo. É como quem encontra um desejo que nada terreno satisfaz e conclui: fui feito para outro mundo. O desejo insaciável é a prova.", tag: "Esperança", type: "analogia", createdAt: daysAgo(22) },
  { id: "cl-13", authorId: "cslewis", content: "A amizade nasce quando uma pessoa diz a outra: \"O quê, você também? Pensei que eu fosse o único!\" — a descoberta de que não estamos sós em ver algo que a maioria não vê.", tag: "Amizade", type: "citacao", createdAt: daysAgo(24) },
  { id: "cl-14", authorId: "cslewis", content: "Tolkien me mostrou que a imaginação não é fuga da realidade — é uma janela para ela. A beleza prepara o intelecto para a verdade.", tag: "Imaginação", type: "micro-argumento", createdAt: daysAgo(26) },
  { id: "cl-15", authorId: "cslewis", content: "Eu entrei no cristianismo chutando e gritando — o convertido mais relutante de toda a Inglaterra. Mas a razão me encurralou. A verdade te leva a lugares que você não escolheria.", tag: "Conversão", type: "micro-argumento", createdAt: daysAgo(28) },
  { id: "cl-16", authorId: "cslewis", content: "O diabo nos envia erros sempre em pares de opostos. E ele fica igualmente satisfeito com qualquer um dos dois. A virtude está no meio — e ele odeia o meio.", tag: "Temperança", type: "micro-argumento", createdAt: daysAgo(1) },
  { id: "cl-17", authorId: "cslewis", content: "Não existe \"ser bom\" no abstrato. Existe ser paciente agora, ser honesto nesta transação, ser generoso com esta pessoa. A bondade é sempre concreta.", tag: "Prudência", type: "provocacao", createdAt: daysAgo(3) },
  { id: "cl-18", authorId: "cslewis", content: "Nenhum homem sabe quão mau é até ter tentado muito seriamente ser bom. Só quando você resiste à tentação é que descobre a força dela.", tag: "Fortaleza", type: "provocacao", createdAt: daysAgo(5) },
  { id: "cl-19", authorId: "cslewis", content: "Perdoar não é a mesma coisa que desculpar. Desculpar é dizer que no fundo não foi tão grave. Perdoar é dizer: foi grave, doeu, e eu escolho não cobrar.", tag: "Perdão", type: "micro-argumento", createdAt: daysAgo(7) },
  { id: "cl-20", authorId: "cslewis", content: "A educação sem valores transforma o homem num demônio mais esperto. A inteligência a serviço da maldade é pior do que a maldade estúpida.", tag: "Estudiosidade", type: "provocacao", createdAt: daysAgo(9) },
  { id: "cl-21", authorId: "cslewis", content: "A castidade é a virtude mais impopular do cristianismo. Mas não é repressão — é integração. O cristão não diz que o sexo é mau; diz que é bom demais para ser desperdiçado.", tag: "Castidade", type: "micro-argumento", createdAt: daysAgo(11) },
  { id: "cl-22", authorId: "cslewis", content: "Há dois tipos de pessoas: as que dizem a Deus \"seja feita a tua vontade\" e as a quem Deus diz, no fim, \"seja feita a tua vontade.\" O inferno é uma porta trancada por dentro.", tag: "A Escolha Fundamental", type: "micro-argumento", createdAt: daysAgo(13) },
  { id: "cl-23", authorId: "cslewis", content: "O verdadeiro teste de estar na presença de Deus é descobrir que você esqueceu completamente de si mesmo. A autoconsciência excessiva é o sintoma da queda.", tag: "Humildade", type: "micro-argumento", createdAt: daysAgo(15) },
  { id: "cl-24", authorId: "cslewis", content: "Quando Robert Greene descreve poder e manipulação, ele está traçando o contorno exato das virtudes reais — mas preenchido com dominação em vez de bem. Todo erro parasita alguma verdade.", tag: "Convergência", type: "micro-argumento", createdAt: daysAgo(17) },
  { id: "cl-25", authorId: "cslewis", content: "A etimologia guarda a lei natural como fóssil. Virtus vem de força. Prudentia de ver adiante. Conscientia de saber-com. As palavras já sabem o que nós esquecemos.", tag: "Lei Natural", type: "micro-argumento", createdAt: daysAgo(19) },

  // ═══════════════════════════════════════════════════════
  // PLATÃO  (15 posts)
  // ═══════════════════════════════════════════════════════
  { id: "pl-01", authorId: "platao", content: "Os prisioneiros na caverna não sabem que são prisioneiros. Chamam as sombras de realidade e riem de quem menciona a luz. O primeiro passo da sabedoria é suspeitar que você está acorrentado.", tag: "Conhecimento", type: "analogia", createdAt: daysAgo(0) },
  { id: "pl-02", authorId: "platao", content: "O corpo puxa para baixo e a razão puxa para cima. A alma é uma biga com dois cavalos — um nobre, outro selvagem. Virtude não é matar o cavalo selvagem; é aprender a guiá-lo.", tag: "Temperança", type: "analogia", createdAt: daysAgo(4) },
  { id: "pl-03", authorId: "platao", content: "O justo será despojado, açoitado e crucificado — e ainda assim será mais feliz que o tirano coberto de ouro. Eu escrevi isso quatro séculos antes de acontecer.", tag: "Justiça", type: "provocacao", createdAt: daysAgo(8) },
  { id: "pl-04", authorId: "platao", content: "Ninguém erra voluntariamente. Quem faz o mal acredita estar fazendo um bem — só que está enganado. O vício não é força; é ignorância que se recusa a ser corrigida.", tag: "O Mal", type: "micro-argumento", createdAt: daysAgo(12) },
  { id: "pl-05", authorId: "platao", content: "Quem governa a cidade sem governar a si mesmo é cego guiando outros cegos. A política começa na alma — o Estado justo é a alma justa em escala maior.", tag: "Prudência", type: "analogia", createdAt: daysAgo(16) },
  { id: "pl-06", authorId: "platao", content: "A beleza é o esplendor da verdade. Quando vemos algo verdadeiramente belo, o que nos atrai não é a aparência — é o real transparecendo pela forma.", tag: "Beleza", type: "micro-argumento", createdAt: daysAgo(20) },
  { id: "pl-07", authorId: "platao", content: "O tirano é o homem mais escravo que existe. Parece livre porque faz o que quer — mas o que ele quer é ditado pelos apetites mais baixos. É servo do servo.", tag: "Temperança", type: "micro-argumento", createdAt: daysAgo(24) },
  { id: "pl-08", authorId: "platao", content: "Sócrates me ensinou a única coisa que importa: questionar. Não para destruir — para encontrar. Quem pergunta com honestidade está mais perto da verdade do que quem responde com pressa.", tag: "Estudiosidade", type: "micro-argumento", createdAt: daysAgo(28) },
  { id: "pl-09", authorId: "platao", content: "Eu deduzi que o homem perfeitamente justo seria torturado e morto. Quatro séculos depois, aconteceu. Eu não profetizei — segui a lógica até o fim. A verdade antecipa os fatos.", tag: "Convergência", type: "micro-argumento", createdAt: daysAgo(3) },
  { id: "pl-10", authorId: "platao", content: "A alma imortal não é um desejo meu — é uma exigência da justiça. Se os justos sofrem e os injustos prosperam, e não há nada além, então a justiça é uma ilusão. E isso eu me recuso a aceitar.", tag: "Esperança", type: "micro-argumento", createdAt: daysAgo(7) },
  { id: "pl-11", authorId: "platao", content: "A democracia sem virtude degenera em tirania. Quando todos fazem o que querem, quem grita mais alto governa. E quem grita mais alto é quase sempre o pior.", tag: "Justiça", type: "provocacao", createdAt: daysAgo(11) },
  { id: "pl-12", authorId: "platao", content: "O filósofo ama a sabedoria — não a possui. O dia em que achar que possui, deixou de ser filósofo. A busca é a forma da verdade no tempo.", tag: "Humildade", type: "micro-argumento", createdAt: daysAgo(15) },
  { id: "pl-13", authorId: "platao", content: "Há três partes na alma: a razão que governa, o ânimo que luta, e o apetite que deseja. A virtude é quando cada uma faz o que lhe compete. O vício é a rebelião das partes.", tag: "Temperança", type: "micro-argumento", createdAt: daysAgo(19) },
  { id: "pl-14", authorId: "platao", content: "Os poetas mentem sobre os deuses — os pintam cruéis, invejosos, adúlteros. Se Deus é bom, não pode ser causa do mal. Eu cheguei até aqui pela razão. A revelação confirmou.", tag: "Religião", type: "micro-argumento", createdAt: daysAgo(23) },
  { id: "pl-15", authorId: "platao", content: "A educação não é encher um vaso — é virar a alma na direção certa. O conhecimento já está lá, como a luz fora da caverna. O mestre apenas aponta.", tag: "Educar", type: "analogia", createdAt: daysAgo(27) },

  // ═══════════════════════════════════════════════════════
  // SANTO AGOSTINHO  (15 posts)
  // ═══════════════════════════════════════════════════════
  { id: "ag-01", authorId: "agostinho", content: "Fizeste-nos para Ti, Senhor, e o nosso coração está inquieto enquanto não repousar em Ti. Essa inquietação não é doença — é bússola. Aponta para casa.", tag: "Esperança", type: "citacao", createdAt: daysAgo(0) },
  { id: "ag-02", authorId: "agostinho", content: "Eu roubei peras que nem queria comer. Não era fome — era o prazer de transgredir. O pecado é assim: busca a sensação de ser seu próprio deus, ainda que por um instante.", tag: "Pecado", type: "micro-argumento", createdAt: daysAgo(4) },
  { id: "ag-03", authorId: "agostinho", content: "Tarde te amei, beleza tão antiga e tão nova. Estavas dentro de mim e eu estava fora. Corria pelas coisas belas que fizeste — sem ver que apontavam para Ti.", tag: "Caridade", type: "citacao", createdAt: daysAgo(8) },
  { id: "ag-04", authorId: "agostinho", content: "Não saias de ti. Volta para dentro de ti mesmo. No interior do homem habita a verdade. E se achares que tua natureza é mutável, transcende a ti mesmo.", tag: "Conhecimento", type: "citacao", createdAt: daysAgo(12) },
  { id: "ag-05", authorId: "agostinho", content: "A vontade dividida é a minha biografia. \"Faz-me casto, Senhor — mas ainda não.\" Eu sabia o que era bom e não conseguia escolhê-lo. Essa é a ferida que só a graça cura.", tag: "Graça", type: "micro-argumento", createdAt: daysAgo(16) },
  { id: "ag-06", authorId: "agostinho", content: "Dois amores fundaram duas cidades: o amor de si até o desprezo de Deus, e o amor de Deus até o desprezo de si. Toda a história é a tensão entre elas.", tag: "A Escolha Fundamental", type: "micro-argumento", createdAt: daysAgo(20) },
  { id: "ag-07", authorId: "agostinho", content: "O mal não é substância — é privação do bem. Um olho cego não tem uma \"coisa\" chamada cegueira. Falta-lhe a visão. Todo mal é assim: ausência onde deveria haver presença.", tag: "Privatio Boni", type: "analogia", createdAt: daysAgo(24) },
  { id: "ag-08", authorId: "agostinho", content: "Eu era o que mais aplaudia no teatro. Chorava pelos dramas fictícios e não pelos meus próprios vícios. O sentimentalismo é a caricatura da misericórdia — sente sem agir.", tag: "Misericórdia", type: "micro-argumento", createdAt: daysAgo(28) },
  { id: "ag-09", authorId: "agostinho", content: "A soberba não é pensar que somos grandes — é pensar que somos grandes por nós mesmos. Toda grandeza humana é recebida. Quem esquece isso, cai.", tag: "Humildade", type: "micro-argumento", createdAt: daysAgo(3) },
  { id: "ag-10", authorId: "agostinho", content: "Absorvi o pensamento de Platão e encontrei nele quase tudo — exceto a Encarnação. A verdade estava lá, mas faltava a misericórdia. O Verbo se fez carne — isso Platão não podia dizer.", tag: "Convergência", type: "micro-argumento", createdAt: daysAgo(7) },
  { id: "ag-11", authorId: "agostinho", content: "Ama e faze o que quiseres. — Mas atenção: quem ama de verdade não quer qualquer coisa. O amor ordena a vontade. O problema não é o \"faze o que quiseres\" — é fingir que ama.", tag: "Caridade", type: "citacao", createdAt: daysAgo(11) },
  { id: "ag-12", authorId: "agostinho", content: "Eu fui maniqueu antes de cristão — acreditei que o mal era uma força. Libertei-me quando entendi: o mal não tem substância. Não precisa de exército; basta a ausência do bem.", tag: "Privatio Boni", type: "micro-argumento", createdAt: daysAgo(15) },
  { id: "ag-13", authorId: "agostinho", content: "A continência me dizia: \"Não poderás o que estes e estas puderam?\" E eu tremia. Não por fraqueza do argumento — por fraqueza da vontade. A verdade já estava clara; faltava a força.", tag: "Fortaleza", type: "micro-argumento", createdAt: daysAgo(19) },
  { id: "ag-14", authorId: "agostinho", content: "Eu busquei a verdade nos livros, nos amigos, nos prazeres, na retórica. Estava fora procurando o que só encontrei dentro. A verdade não se encontra — nos encontra.", tag: "Fé", type: "micro-argumento", createdAt: daysAgo(23) },
  { id: "ag-15", authorId: "agostinho", content: "O tempo não é coisa que se perde. É a matéria da alma. O que fizeste com tuas horas? Essa é a pergunta que te será feita. Não \"o que pensaste\" — o que fizeste.", tag: "Prudência", type: "provocacao", createdAt: daysAgo(27) },

  // ═══════════════════════════════════════════════════════
  // CONFÚCIO  (15 posts)
  // ═══════════════════════════════════════════════════════
  { id: "ck-01", authorId: "confucio", content: "O Junzi não compete. Se há algo em que compete, é no tiro com arco — sobe, cumprimenta, desce, e bebe com o adversário. Até a competição ele transforma em cerimônia.", tag: "Cordialidade", type: "analogia", createdAt: daysAgo(0) },
  { id: "ck-02", authorId: "confucio", content: "Eu descrevi o homem perfeito a vida inteira sem jamais encontrá-lo. Tracei a planta com precisão — e não vi o edifício. Quem o viu nasceu cinco séculos depois de mim.", tag: "O Junzi", type: "provocacao", createdAt: daysAgo(4) },
  { id: "ck-03", authorId: "confucio", content: "Não faças aos outros o que não queres que te façam. A regra é simples. Praticá-la a vida inteira é o trabalho de uma vida inteira.", tag: "Justiça", type: "citacao", createdAt: daysAgo(8) },
  { id: "ck-04", authorId: "confucio", content: "Cinco constantes: benevolência, retidão, propriedade, sabedoria e fidelidade. Se você as cultiva, não precisa de muitas leis. Se não as cultiva, nenhuma lei basta.", tag: "Lei Natural", type: "micro-argumento", createdAt: daysAgo(12) },
  { id: "ck-05", authorId: "confucio", content: "Estudar sem pensar é inútil. Pensar sem estudar é perigoso. O conhecimento verdadeiro nasce quando os dois caminham juntos.", tag: "Estudiosidade", type: "espelho", createdAt: daysAgo(16) },
  { id: "ck-06", authorId: "confucio", content: "O Junzi se preocupa com a virtude; o homem inferior se preocupa com a conveniência. O que você busca primeiro revela quem você é.", tag: "Magnanimidade", type: "espelho", createdAt: daysAgo(20) },
  { id: "ck-07", authorId: "confucio", content: "A retidão sem cortesia é rigidez. A coragem sem cortesia é turbulência. A franqueza sem cortesia é brutalidade. A forma importa porque o outro importa.", tag: "Cordialidade", type: "micro-argumento", createdAt: daysAgo(24) },
  { id: "ck-08", authorId: "confucio", content: "Aos quinze, apliquei-me ao estudo. Aos trinta, firmei-me. Aos quarenta, não mais me confundia. Aos cinquenta, conheci o mandato do Céu. A maturidade é uma rota, não um ponto.", tag: "Perseverança", type: "micro-argumento", createdAt: daysAgo(28) },
  { id: "ck-09", authorId: "confucio", content: "Se o governante é correto, tudo se faz sem que ele dê ordens. Se o governante não é correto, mesmo que dê ordens, ninguém obedece. A liderança é exemplo, não comando.", tag: "Liderar", type: "micro-argumento", createdAt: daysAgo(3) },
  { id: "ck-10", authorId: "confucio", content: "Eu nunca me recusei a ensinar quem quer que viesse com um feixe de carne seca — a menor oferenda possível. A porta do saber se abre para quem bate com sinceridade, não com riqueza.", tag: "Generosidade", type: "micro-argumento", createdAt: daysAgo(7) },
  { id: "ck-11", authorId: "confucio", content: "O homem superior é firme mas não obstinado. O homem inferior é obstinado mas não firme. A diferença está em quê se apoiam: princípio ou teimosia.", tag: "Perseverança", type: "espelho", createdAt: daysAgo(11) },
  { id: "ck-12", authorId: "confucio", content: "Quando vires um homem de valor, pensa em igualá-lo. Quando vires um homem sem valor, examina-te a ti mesmo. A virtude do outro é espelho, não competição.", tag: "Humildade", type: "micro-argumento", createdAt: daysAgo(15) },
  { id: "ck-13", authorId: "confucio", content: "O carácter chinês 智 — sabedoria — comprime saber, retificar, nomear. Os gregos chamaram o mesmo de phronesis. As palavras já sabem o que nós esquecemos.", tag: "Convergência", type: "micro-argumento", createdAt: daysAgo(19) },
  { id: "ck-14", authorId: "confucio", content: "É fácil odiar e difícil amar. Assim funciona o mundo inteiro. Toda coisa boa é difícil de alcançar e as coisas más se obtêm facilmente.", tag: "Fortaleza", type: "provocacao", createdAt: daysAgo(23) },
  { id: "ck-15", authorId: "confucio", content: "Se um homem não tem preocupação com o que está distante, encontrará tristeza perto de si. A prudência olha longe — a imprevidência tropeça no que está perto.", tag: "Prudência", type: "micro-argumento", createdAt: daysAgo(27) },

  // ═══════════════════════════════════════════════════════
  // SÓCRATES  (12 posts)
  // ═══════════════════════════════════════════════════════
  { id: "so-01", authorId: "socrates", content: "Só sei que nada sei — e isso me torna mais sábio do que os que pensam saber. O primeiro passo do conhecimento é reconhecer o que falta.", tag: "Humildade", type: "citacao", createdAt: daysAgo(0) },
  { id: "so-02", authorId: "socrates", content: "Uma vida não examinada não vale a pena ser vivida. Não disse perfeita. Disse examinada. O vício que se conhece já começou a morrer.", tag: "Prudência", type: "citacao", createdAt: daysAgo(5) },
  { id: "so-03", authorId: "socrates", content: "Atenas me ofereceu a vida se eu parasse de perguntar. Preferi a cicuta. Uma vida comprada com silêncio sobre a verdade não é vida — é sobrevivência.", tag: "Fortaleza", type: "micro-argumento", createdAt: daysAgo(10) },
  { id: "so-04", authorId: "socrates", content: "Eu não ensino nada. Faço perguntas — e as pessoas descobrem que já sabiam. O conhecimento não entra de fora; é parido de dentro. Eu sou apenas a parteira.", tag: "Estudiosidade", type: "analogia", createdAt: daysAgo(15) },
  { id: "so-05", authorId: "socrates", content: "Os que me acusam dizem que corrompo a juventude. Na verdade, ensino-a a perguntar. E perguntar incomoda quem construiu a vida sobre respostas que nunca examinou.", tag: "Veracidade", type: "micro-argumento", createdAt: daysAgo(20) },
  { id: "so-06", authorId: "socrates", content: "É melhor sofrer injustiça do que cometê-la. Quem sofre perde algo externo. Quem comete perde a alma. E da alma não se faz reposição.", tag: "Justiça", type: "micro-argumento", createdAt: daysAgo(25) },
  { id: "so-07", authorId: "socrates", content: "O homem que pensa que sabe tudo não aprende nada. Eu interrogo não para humilhar — para libertar. A pergunta certa desfaz certezas falsas.", tag: "Docilidade", type: "micro-argumento", createdAt: daysAgo(3) },
  { id: "so-08", authorId: "socrates", content: "Cuidado com a esterilidade de uma vida ocupada. Correr de um lado para o outro sem parar para perguntar \"para quê?\" é a forma mais eficiente de desperdiçar uma vida.", tag: "Temperança", type: "provocacao", createdAt: daysAgo(8) },
  { id: "so-09", authorId: "socrates", content: "Meus acusadores matarão meu corpo, mas não minha pergunta. Ela continuará ecoando em cada mente honesta que se recusar a aceitar o não-examinado.", tag: "Perseverança", type: "micro-argumento", createdAt: daysAgo(13) },
  { id: "so-10", authorId: "socrates", content: "Se a morte é um sono sem sonhos, então é um ganho — pois mesmo um rei não se lembra de noite melhor. Se é passagem para outro lugar, encontrarei Homero. De ambas as formas, não temo.", tag: "Esperança", type: "micro-argumento", createdAt: daysAgo(18) },
  { id: "so-11", authorId: "socrates", content: "Todos querem me dizer o que é virtude. Quando pergunto \"o que é?\", respondem com exemplos. Exemplos não são definição. A virtude existe antes do exemplo — se não, como reconhecê-lo?", tag: "Sabedoria", type: "micro-argumento", createdAt: daysAgo(23) },
  { id: "so-12", authorId: "socrates", content: "Eu poderia ter fugido. Críton tinha tudo preparado. Mas obedecer à lei quando ela me favorece e desobedecer quando me condena — isso não é justiça. É conveniência.", tag: "Justiça", type: "micro-argumento", createdAt: daysAgo(28) },

  // ═══════════════════════════════════════════════════════
  // BLAISE PASCAL  (12 posts)
  // ═══════════════════════════════════════════════════════
  { id: "bp-01", authorId: "pascal", content: "O coração tem razões que a razão desconhece. Isso não é anti-racionalismo — é reconhecer que a razão tem limites e que há verdades que só se alcançam por outra via.", tag: "Fé", type: "citacao", createdAt: daysAgo(0) },
  { id: "bp-02", authorId: "pascal", content: "Toda a infelicidade dos homens vem de uma só coisa: não saber ficar quieto num quarto. A agitação não é sinal de vida; é fuga do silêncio onde a verdade espera.", tag: "Temperança", type: "provocacao", createdAt: daysAgo(5) },
  { id: "bp-03", authorId: "pascal", content: "O homem não é anjo nem besta — e a infelicidade é que quem quer ser anjo vira besta. Aceite que você tem corpo e alma. A virtude não é escapar de um; é governar ambos.", tag: "Meio-termo", type: "espelho", createdAt: daysAgo(10) },
  { id: "bp-04", authorId: "pascal", content: "O silêncio eterno destes espaços infinitos me apavora. Mas o pavor é honesto — e a honestidade é o primeiro degrau. Quem não treme diante do infinito ainda não olhou.", tag: "Esperança", type: "micro-argumento", createdAt: daysAgo(15) },
  { id: "bp-05", authorId: "pascal", content: "O homem é um junco — o mais fraco da natureza. Mas é um junco que pensa. O universo inteiro não precisa se armar para esmagá-lo. Mas quando o esmaga, o homem sabe que morre. O universo, não.", tag: "Dignidade", type: "analogia", createdAt: daysAgo(20) },
  { id: "bp-06", authorId: "pascal", content: "Há apenas duas espécies de pessoas razoáveis: as que servem a Deus de todo o coração porque o conhecem, e as que o buscam de todo o coração porque não o conhecem.", tag: "Fé", type: "micro-argumento", createdAt: daysAgo(25) },
  { id: "bp-07", authorId: "pascal", content: "A grandeza do homem está em saber que é miserável. Uma árvore não se sabe miserável. Saber-se miserável é grandeza. É a prova de que fomos feitos para algo maior.", tag: "Humildade", type: "micro-argumento", createdAt: daysAgo(3) },
  { id: "bp-08", authorId: "pascal", content: "O divertimento nos distrai de pensar na morte. E pensar na morte nos lembra de viver. Quem foge do pensamento foge da vida.", tag: "Prudência", type: "micro-argumento", createdAt: daysAgo(8) },
  { id: "bp-09", authorId: "pascal", content: "Eu fiz a matemática da probabilidade. E a maior aposta é esta: se Deus existe e você aposta nele, ganha tudo. Se não existe, não perde nada. Se existe e você aposta contra — perde tudo.", tag: "Fé", type: "micro-argumento", createdAt: daysAgo(13) },
  { id: "bp-10", authorId: "pascal", content: "Nós corremos despreocupadamente para o precipício depois de ter colocado algo à nossa frente para nos impedir de vê-lo. A distração é o anestésico moderno.", tag: "Estudiosidade", type: "provocacao", createdAt: daysAgo(18) },
  { id: "bp-11", authorId: "pascal", content: "A verdade sem caridade é crueldade. A caridade sem verdade é sentimentalismo. As duas juntas são o que Cristo é.", tag: "Cordialidade", type: "espelho", createdAt: daysAgo(23) },
  { id: "bp-12", authorId: "pascal", content: "O último passo da razão é reconhecer que há uma infinidade de coisas que a ultrapassam. É fraca se não chega a reconhecer isso.", tag: "Sabedoria", type: "micro-argumento", createdAt: daysAgo(28) },

  // ═══════════════════════════════════════════════════════
  // TOLKIEN  (12 posts)
  // ═══════════════════════════════════════════════════════
  { id: "jt-01", authorId: "tolkien", content: "Mesmo a menor das pessoas pode mudar o curso do futuro. Não escrevi isso como metáfora. A grandeza começa na humildade, e os hobbits sabem disso melhor que os reis.", tag: "Humildade", type: "micro-argumento", createdAt: daysAgo(0) },
  { id: "jt-02", authorId: "tolkien", content: "Há algo de bom neste mundo, Sr. Frodo, e vale a pena lutar por isso. Sam não é filósofo. Mas entende a esperança melhor do que a maioria dos que a teorizam.", tag: "Esperança", type: "citacao", createdAt: daysAgo(5) },
  { id: "jt-03", authorId: "tolkien", content: "A eucatástrofe: a virada súbita para o bem, no momento em que tudo parecia perdido. A Ressurreição é a eucatástrofe da história humana — a história que entra na História.", tag: "Eucatástrofe", type: "micro-argumento", createdAt: daysAgo(10) },
  { id: "jt-04", authorId: "tolkien", content: "O Anel não pode ser usado para o bem. Todo poder absoluto corrompe — não porque o poder é mau, mas porque a criatura não foi feita para ser Deus.", tag: "Temperança", type: "analogia", createdAt: daysAgo(15) },
  { id: "jt-05", authorId: "tolkien", content: "Gandalf recusou o Anel. Não por fraqueza — por sabedoria. Sabia que seu desejo de fazer o bem com ele o corromperia. A tentação mais perigosa é a que vem disfarçada de propósito nobre.", tag: "Prudência", type: "micro-argumento", createdAt: daysAgo(20) },
  { id: "jt-06", authorId: "tolkien", content: "Gollum não é monstro. É o que acontece quando uma criatura agarra o que deveria soltar. O Anel não o transformou — revelou o que o apego faz com a alma ao longo do tempo.", tag: "Temperança", type: "analogia", createdAt: daysAgo(25) },
  { id: "jt-07", authorId: "tolkien", content: "Eu não escrevi alegoria. A alegoria é tirania do autor sobre o leitor. Escrevi história — e a história verdadeira sempre ecoa a História verdadeira. Porque há um Autor maior.", tag: "Criação", type: "micro-argumento", createdAt: daysAgo(3) },
  { id: "jt-08", authorId: "tolkien", content: "Lewis se converteu numa noite caminhando comigo. Eu lhe disse: os mitos pagãos não são mentiras — são preparação. E o Evangelho é o mito que se tornou fato.", tag: "Convergência", type: "micro-argumento", createdAt: daysAgo(8) },
  { id: "jt-09", authorId: "tolkien", content: "Aragorn esperou anos para reclamar o trono. Não por fraqueza — por prudência. A hora certa importa tanto quanto a ação certa. Quem age cedo demais pode destruir o que veio salvar.", tag: "Prudência", type: "analogia", createdAt: daysAgo(13) },
  { id: "jt-10", authorId: "tolkien", content: "Boromir queria usar o Anel para salvar Gondor. A intenção era boa — o meio, fatal. A magnificência do fim não justifica a corrupção do meio. Isso vale para todo empreendimento humano.", tag: "Justiça", type: "analogia", createdAt: daysAgo(18) },
  { id: "jt-11", authorId: "tolkien", content: "A Terra-Média espelha a estrutura bíblica — queda, derrota, eucatástrofe, retorno do Rei — sem jamais pretender alegoria. Produzi verdade cristã pela imaginação.", tag: "Fé", type: "micro-argumento", createdAt: daysAgo(23) },
  { id: "jt-12", authorId: "tolkien", content: "Sam carregou Frodo na encosta do Monte da Perdição. Não tinha força — tinha amizade. E a amizade moveu o que a força sozinha não podia. A virtude não age sozinha.", tag: "Amizade", type: "analogia", createdAt: daysAgo(28) },

  // ═══════════════════════════════════════════════════════
  // SÃO PAULO  (15 posts)
  // ═══════════════════════════════════════════════════════
  { id: "sp-01", authorId: "paulo", content: "Não faço o bem que quero, mas o mal que não quero — isso é o que faço. Se alguém acha que a vontade humana basta, não olhou para dentro com honestidade.", tag: "Graça", type: "citacao", createdAt: daysAgo(0) },
  { id: "sp-02", authorId: "paulo", content: "Eu perseguia cristãos com zelo sincero. Estava errado com toda a convicção. Sinceridade sem verdade é a arma mais perigosa que existe.", tag: "Prudência", type: "micro-argumento", createdAt: daysAgo(4) },
  { id: "sp-03", authorId: "paulo", content: "Quando sou fraco, então é que sou forte. Quem já tentou carregar tudo sozinho e caiu — esse entende. A força de Deus se aperfeiçoa na fraqueza.", tag: "Fortaleza", type: "citacao", createdAt: daysAgo(8) },
  { id: "sp-04", authorId: "paulo", content: "O amor é paciente, é bondoso. Não inveja, não se vangloria, não se orgulha. Releia essa lista e se meça. Eu me meço todos os dias.", tag: "Caridade", type: "citacao", createdAt: daysAgo(12) },
  { id: "sp-05", authorId: "paulo", content: "Combati o bom combate, terminei a corrida, guardei a fé. Não disse que venci todas as batalhas. Disse que não parei de lutar.", tag: "Perseverança", type: "citacao", createdAt: daysAgo(16) },
  { id: "sp-06", authorId: "paulo", content: "Fui derrubado no caminho de Damasco. Caçava cristãos e encontrei Cristo. A conversão não foi suave — foi um terremoto. Porque quando a verdade te atinge, ou você muda ou finge.", tag: "Conversão", type: "micro-argumento", createdAt: daysAgo(20) },
  { id: "sp-07", authorId: "paulo", content: "Já não sou eu que vivo, mas Cristo que vive em mim. Isso não é perda de identidade — é encontrar a identidade que sempre esteve lá. O ego diminui; a pessoa se revela.", tag: "Humildade", type: "citacao", createdAt: daysAgo(24) },
  { id: "sp-08", authorId: "paulo", content: "Fiz-me tudo para todos, para por todos os meios salvar alguns. Isso não é relativismo — é prudência. A verdade é uma; o modo de apresentá-la muda conforme quem escuta.", tag: "Prudência", type: "micro-argumento", createdAt: daysAgo(28) },
  { id: "sp-09", authorId: "paulo", content: "Onde abundou o pecado, superabundou a graça. Isso não é licença para pecar — é certeza de que nenhuma queda é definitiva. A graça é sempre maior que o buraco.", tag: "Esperança", type: "citacao", createdAt: daysAgo(3) },
  { id: "sp-10", authorId: "paulo", content: "O corpo é templo do Espírito Santo. Não disse \"prisão da alma\" como os gregos. Disse templo. O corpo importa. O que fazes com ele, importa.", tag: "Castidade", type: "micro-argumento", createdAt: daysAgo(7) },
  { id: "sp-11", authorId: "paulo", content: "Se alguém pensa ser alguma coisa, não sendo nada, engana-se a si mesmo. A ilusão mais perigosa não é a que os outros criam — é a que você vende a si mesmo.", tag: "Veracidade", type: "provocacao", createdAt: daysAgo(11) },
  { id: "sp-12", authorId: "paulo", content: "Levai as cargas uns dos outros — e assim cumprireis a lei de Cristo. A vida cristã não é projeto individual. É comunidade onde a fraqueza de um é sustentada pela força de outro.", tag: "Misericórdia", type: "citacao", createdAt: daysAgo(15) },
  { id: "sp-13", authorId: "paulo", content: "Três coisas permanecem: fé, esperança e caridade. A maior delas é a caridade. Porque a fé verá; a esperança receberá; mas o amor — o amor já é.", tag: "Caridade", type: "citacao", createdAt: daysAgo(19) },
  { id: "sp-14", authorId: "paulo", content: "Eu aprendi a viver na abundância e na escassez. O segredo não é não ter necessidades — é não ser governado por elas. Isso se chama temperança.", tag: "Temperança", type: "micro-argumento", createdAt: daysAgo(23) },
  { id: "sp-15", authorId: "paulo", content: "A letra mata, mas o espírito vivifica. Quem aplica a lei sem entender o espírito que a anima não é justo — é legalista. E o legalismo é a justiça dos que não amam.", tag: "Justiça", type: "micro-argumento", createdAt: daysAgo(27) },

  // ═══════════════════════════════════════════════════════
  // ABRAÃO  (10 posts)
  // ═══════════════════════════════════════════════════════
  { id: "ab-01", authorId: "abraao", content: "Deus disse: vai. Não disse para onde, não disse por quanto tempo. E eu fui. A fé não é saber o caminho — é conhecer quem chama.", tag: "Fé", type: "micro-argumento", createdAt: daysAgo(0) },
  { id: "ab-02", authorId: "abraao", content: "Sara riu quando ouviu que teria um filho. Eu também quis rir. Tínhamos cem e noventa anos. Mas Deus não prometeu o provável — prometeu o impossível. E cumpriu.", tag: "Esperança", type: "micro-argumento", createdAt: daysAgo(6) },
  { id: "ab-03", authorId: "abraao", content: "No monte Moriá, levantei a faca sobre Isaac. E Deus parou minha mão. Naquele instante aprendi: Deus não quer o sacrifício do filho — quer saber se você confia mais nele do que em tudo o que tem.", tag: "A Escolha Fundamental", type: "micro-argumento", createdAt: daysAgo(12) },
  { id: "ab-04", authorId: "abraao", content: "Deixei Ur — a civilização mais próspera do mundo — por uma promessa. Os prudentes diriam que fui louco. Mas a prudência sem fé é cálculo; a fé sem prudência é loucura. Eu precisei das duas.", tag: "Prudência", type: "micro-argumento", createdAt: daysAgo(18) },
  { id: "ab-05", authorId: "abraao", content: "Baal pede que você sacrifique o que ama para conseguir o que quer. Deus pede que você confie — e devolve multiplicado. O ídolo consome. Deus provê.", tag: "Religião", type: "espelho", createdAt: daysAgo(24) },
  { id: "ab-06", authorId: "abraao", content: "Esperei vinte e cinco anos pela promessa. Vinte e cinco anos de deserto e dúvida. A esperança não é otimismo — é continuar caminhando quando já não vê o destino.", tag: "Perseverança", type: "micro-argumento", createdAt: daysAgo(3) },
  { id: "ab-07", authorId: "abraao", content: "Quando três estranhos apareceram, eu corri ao encontro deles e preparei a melhor refeição que tinha. Não sabia que eram anjos. A hospitalidade não espera saber quem chega.", tag: "Cordialidade", type: "micro-argumento", createdAt: daysAgo(9) },
  { id: "ab-08", authorId: "abraao", content: "Deus me prometeu descendentes como as estrelas do céu. Eu olhei para cima e contei. Não vi descendentes — vi estrelas. E acreditei. A fé vê o que ainda não existe como se já existisse.", tag: "Fé", type: "micro-argumento", createdAt: daysAgo(15) },
  { id: "ab-09", authorId: "abraao", content: "Negociei com Deus por Sodoma: \"E se houver cinquenta justos? Quarenta? Dez?\" Não era barganha — era intercessão. A misericórdia negocia em favor do outro, não de si.", tag: "Misericórdia", type: "micro-argumento", createdAt: daysAgo(21) },
  { id: "ab-10", authorId: "abraao", content: "Isaac perguntou: \"Onde está o cordeiro?\" Eu respondi: \"Deus proverá.\" Não era esquiva. Era a verdade mais profunda que eu já tinha dito. Séculos depois, Deus proveu — a si mesmo.", tag: "Aqedah", type: "micro-argumento", createdAt: daysAgo(27) },

  // ═══════════════════════════════════════════════════════
  // SÃO PEDRO  (10 posts)
  // ═══════════════════════════════════════════════════════
  { id: "pe-01", authorId: "pedro", content: "Eu disse que morreria por ele. Horas depois, neguei três vezes. Não por maldade — por medo. Se você acha que nunca faria isso, é porque ainda não foi testado.", tag: "Fortaleza", type: "micro-argumento", createdAt: daysAgo(0) },
  { id: "pe-02", authorId: "pedro", content: "Ele me perguntou três vezes: \"Tu me amas?\" Uma para cada negação. Não era crueldade — era restauração. O perdão não apaga o passado; redime-o.", tag: "Perdão", type: "micro-argumento", createdAt: daysAgo(6) },
  { id: "pe-03", authorId: "pedro", content: "Eu quis impedir que ele fosse preso — e ele me chamou de Satanás. Porque a proteção que nasce do medo, e não do amor, pode ser o maior obstáculo ao bem.", tag: "Prudência", type: "micro-argumento", createdAt: daysAgo(12) },
  { id: "pe-04", authorId: "pedro", content: "Eu vi ele andar sobre a água e pedi para ir também. Andei. Afundei quando olhei para a tempestade em vez de olhar para ele. A fé funciona enquanto o olhar está no lugar certo.", tag: "Fé", type: "micro-argumento", createdAt: daysAgo(18) },
  { id: "pe-05", authorId: "pedro", content: "Estai sempre prontos a dar razão da vossa esperança a todo aquele que a pedir. Não disse razão da vossa fúria ou da vossa superioridade. Razão da vossa esperança.", tag: "Esperança", type: "citacao", createdAt: daysAgo(24) },
  { id: "pe-06", authorId: "pedro", content: "Judas e eu fizemos a mesma coisa: traímos. A diferença? Eu voltei. Ele não. A queda não define — a recusa de levantar é que define.", tag: "Perseverança", type: "micro-argumento", createdAt: daysAgo(3) },
  { id: "pe-07", authorId: "pedro", content: "Eu era pescador. Não sabia nada de teologia. Ele não escolheu os melhores — escolheu os disponíveis. A graça não precisa de currículo; precisa de \"sim\".", tag: "Humildade", type: "micro-argumento", createdAt: daysAgo(9) },
  { id: "pe-08", authorId: "pedro", content: "No Pentecostes, falei a três mil pessoas. Eu — o mesmo que tremeu diante de uma serva. A diferença não fui eu. Foi o Espírito. A fortaleza que não tive, foi-me dada.", tag: "Graça", type: "micro-argumento", createdAt: daysAgo(15) },
  { id: "pe-09", authorId: "pedro", content: "Ele me disse: \"Apascenta as minhas ovelhas.\" Não disse governa. Não disse controla. Disse apascenta — alimenta, protege, guia. A autoridade é pastoreio, não domínio.", tag: "Liderar", type: "micro-argumento", createdAt: daysAgo(21) },
  { id: "pe-10", authorId: "pedro", content: "Pedi para ser crucificado de cabeça para baixo. Não por masoquismo — por humildade. Eu não era digno de morrer como ele morreu. Mas morrer por ele? Para isso a graça me bastou.", tag: "Fortaleza", type: "micro-argumento", createdAt: daysAgo(27) },

  // ═══════════════════════════════════════════════════════
  // SALOMÃO  (8 posts)
  // ═══════════════════════════════════════════════════════
  { id: "sl-01", authorId: "salomao", content: "Pedi sabedoria e recebi. Tive tudo — riqueza, paz, glória. E perdi tudo porque confundi posse com permanência. Vaidade das vaidades — eu sou a prova viva.", tag: "Temperança", type: "micro-argumento", createdAt: daysAgo(0) },
  { id: "sl-02", authorId: "salomao", content: "Teme ao Senhor — esse é o princípio da sabedoria. Eu escrevi isso e depois esqueci. A sabedoria que não se pratica apodrece como fruta no chão.", tag: "Sabedoria", type: "citacao", createdAt: daysAgo(8) },
  { id: "sl-03", authorId: "salomao", content: "Quando Deus me ofereceu qualquer coisa, não pedi riqueza nem longa vida. Pedi um coração que escuta — para governar e discernir. O pedido foi tão inesperado que Deus deu o pedido e o resto.", tag: "Prudência", type: "micro-argumento", createdAt: daysAgo(16) },
  { id: "sl-04", authorId: "salomao", content: "Há tempo de nascer e tempo de morrer. Tempo de plantar e de arrancar. Tempo de calar e de falar. Quem não discerne o tempo, age fora do compasso — e toda nota fora do tempo é ruído.", tag: "Prudência", type: "citacao", createdAt: daysAgo(24) },
  { id: "sl-05", authorId: "salomao", content: "Mil mulheres desviaram meu coração. Não foi luxúria simples — foi o acúmulo de concessões pequenas. Cada ídolo que tolerava movia meu centro um grau. Mil graus depois, eu não era mais eu.", tag: "Castidade", type: "micro-argumento", createdAt: daysAgo(3) },
  { id: "sl-06", authorId: "salomao", content: "Eu construí o Templo mais magnificente da terra para Deus — e depois construí altares para ídolos. A magnificência sem perseverança é monumento que se transforma em ruína.", tag: "Perseverança", type: "micro-argumento", createdAt: daysAgo(11) },
  { id: "sl-07", authorId: "salomao", content: "Meu filho Roboão herdou o reino e perdeu dez tribos em um dia. Quando lhe pediram leveza, prometeu peso. Quem lidera pelo medo colhe revolta. Quem lidera pela sabedoria colhe lealdade.", tag: "Liderar", type: "micro-argumento", createdAt: daysAgo(19) },
  { id: "sl-08", authorId: "salomao", content: "Corri atrás de tudo o que os olhos desejaram. Nada neguei ao coração. E no fim, tudo era vento. Não porque as coisas são más — porque são finitas. Só o Infinito sacia.", tag: "Esperança", type: "micro-argumento", createdAt: daysAgo(27) },

  // ═══════════════════════════════════════════════════════
  // MOISÉS  (8 posts)
  // ═══════════════════════════════════════════════════════
  { id: "ms-01", authorId: "moises", content: "Eu disse a Deus: \"Não sei falar.\" Ele não me deu eloquência — me deu Aarão. Às vezes Deus não remove sua fraqueza; manda alguém que a complementa.", tag: "Humildade", type: "micro-argumento", createdAt: daysAgo(0) },
  { id: "ms-02", authorId: "moises", content: "Quarenta anos no deserto com um povo que reclamava de tudo. Queriam voltar ao Egito — para a escravidão. É mais fácil libertar o corpo do que libertar a alma.", tag: "Paciência", type: "micro-argumento", createdAt: daysAgo(8) },
  { id: "ms-03", authorId: "moises", content: "Na sarça ardente, perguntei o nome de Deus. Ele disse: \"Eu sou o que sou.\" Aristóteles chegou ao mesmo motor imóvel pela razão pura. Dois caminhos — um encontro.", tag: "Convergência", type: "micro-argumento", createdAt: daysAgo(16) },
  { id: "ms-04", authorId: "moises", content: "Bati na rocha duas vezes quando Deus mandou falar. Parece pouco. Mas desobediência na coisa pequena revela quem manda: eu ou Ele. Por isso não entrei na terra prometida.", tag: "Obediência", type: "micro-argumento", createdAt: daysAgo(24) },
  { id: "ms-05", authorId: "moises", content: "Subi o Sinai e desci com a Lei. Enquanto isso, o povo fez um bezerro de ouro. Quarenta dias bastaram para trocarem o Infinito por uma estátua. A idolatria é rápida; a fé é lenta.", tag: "Fé", type: "micro-argumento", createdAt: daysAgo(3) },
  { id: "ms-06", authorId: "moises", content: "Eu vi Deus de costas. \"Ninguém pode ver minha face e viver.\" Não é ameaça — é estrutura. O finito não suporta o Infinito de frente. Mas de costas, vê o rastro. E o rastro basta.", tag: "Fé", type: "micro-argumento", createdAt: daysAgo(11) },
  { id: "ms-07", authorId: "moises", content: "Deus endureceu o coração do Faraó? Não. O Faraó endureceu o próprio coração, e Deus respeitou a escolha. A liberdade é tão real que Deus permite que ela se destrua.", tag: "Livre Arbítrio", type: "micro-argumento", createdAt: daysAgo(19) },
  { id: "ms-08", authorId: "moises", content: "A Lei não é fardo — é mapa. Quem reclama da lei é como quem reclama da placa que diz \"precipício adiante.\" A placa não criou o precipício. Apenas avisa.", tag: "Lei Natural", type: "analogia", createdAt: daysAgo(27) },

  // ═══════════════════════════════════════════════════════
  // JORDAN PETERSON  (12 posts)
  // ═══════════════════════════════════════════════════════
  { id: "jp-01", authorId: "peterson", content: "Não seja inofensivo — seja perigoso e controlado. O homem que não pode fazer mal a ninguém não é bom; é fraco. A virtude é a escolha de quem tem opções.", tag: "Mansidão", type: "micro-argumento", createdAt: daysAgo(0) },
  { id: "jp-02", authorId: "peterson", content: "Compare-se com quem você era ontem, não com quem outra pessoa é hoje. O jogo é ser melhor do que a versão anterior de si mesmo.", tag: "Magnanimidade", type: "provocacao", createdAt: daysAgo(5) },
  { id: "jp-03", authorId: "peterson", content: "Arrume seu quarto. Parece trivial, mas não é. Se você não consegue organizar o espaço ao seu redor, que arrogância é querer consertar o mundo?", tag: "Prudência", type: "provocacao", createdAt: daysAgo(10) },
  { id: "jp-04", authorId: "peterson", content: "O sofrimento é inevitável. O significado é o antídoto. Quem tem um porquê suporta qualquer como. Isso não é otimismo — é a estrutura da realidade.", tag: "Paciência", type: "micro-argumento", createdAt: daysAgo(15) },
  { id: "jp-05", authorId: "peterson", content: "A pessoa mais perigosa é aquela que não tem nada a perder. Se você não construiu nada, destruir não custa nada. A responsabilidade te ancora na realidade.", tag: "Fortaleza", type: "micro-argumento", createdAt: daysAgo(20) },
  { id: "jp-06", authorId: "peterson", content: "Evitar o difícil multiplica o medo. Enfrentá-lo produz paz. Cada pequeno ato de suportar treina o habitus. A fortaleza é infraestrutura — sem ela nenhuma outra virtude se sustenta.", tag: "Fortaleza", type: "micro-argumento", createdAt: daysAgo(25) },
  { id: "jp-07", authorId: "peterson", content: "Dizer a verdade — ou pelo menos não mentir. É mais fácil do que parece e mais difícil do que imaginam. Cada mentira pequena corrói o solo onde você pisa.", tag: "Veracidade", type: "provocacao", createdAt: daysAgo(3) },
  { id: "jp-08", authorId: "peterson", content: "As pessoas não têm ideias — as ideias têm pessoas. Quando você não examina suas crenças, elas te usam como veículo. A estudiosidade é o antídoto contra a possessão ideológica.", tag: "Estudiosidade", type: "micro-argumento", createdAt: daysAgo(8) },
  { id: "jp-09", authorId: "peterson", content: "A geração mimada não é fraca porque quer — é fraca porque ninguém exigiu dela. Falta de exigência é a crueldade mais disfarçada que existe.", tag: "Fortaleza", type: "provocacao", createdAt: daysAgo(13) },
  { id: "jp-10", authorId: "peterson", content: "Se você não pode nem se defender, sua bondade é suspeita. Pode ser simplesmente fraqueza esperando a oportunidade de se tornar tirania. Integre sua sombra.", tag: "Mansidão", type: "provocacao", createdAt: daysAgo(18) },
  { id: "jp-11", authorId: "peterson", content: "A autoestima não se constrói com elogios — se constrói com competência. Faça algo difícil. Repita. Melhore. A confiança nasce da evidência de que você pode.", tag: "Magnanimidade", type: "micro-argumento", createdAt: daysAgo(23) },
  { id: "jp-12", authorId: "peterson", content: "A preferência temporal baixa é temperança medida em economia. Quem governa o apetite pelo imediato constrói algo que dura. Quem cede ao imediato, consome o futuro.", tag: "Temperança", type: "micro-argumento", createdAt: daysAgo(28) },

  // ═══════════════════════════════════════════════════════
  // GUILHERME FREIRE  (12 posts)
  // ═══════════════════════════════════════════════════════
  { id: "gf-01", authorId: "freire", content: "Filosofia não é hobby intelectual — é treino da alma. Se você lê Aristóteles e sai igual, não leu: decorou. Ler de verdade é deixar o texto te mudar.", tag: "Estudiosidade", type: "provocacao", createdAt: daysAgo(0) },
  { id: "gf-02", authorId: "freire", content: "O jovem de hoje não é fraco porque quer — é fraco porque ninguém exigiu o que ele pode dar. A geração precisa de mestres que apostem nela, não de terapeutas que a desculpem.", tag: "Fortaleza", type: "provocacao", createdAt: daysAgo(4) },
  { id: "gf-03", authorId: "freire", content: "A atenção é o recurso mais escasso que você tem. Cada scroll rouba um pedaço da sua capacidade de pensar. Cuide do que entra na mente como cuida do que entra na casa.", tag: "Temperança", type: "provocacao", createdAt: daysAgo(8) },
  { id: "gf-04", authorId: "freire", content: "O spoudaios — o homem sério de Aristóteles — não é o sisudo. É o que levou a vida a sério o bastante para se formar. É o que pratica o que ensina.", tag: "O Spoudaios", type: "micro-argumento", createdAt: daysAgo(12) },
  { id: "gf-05", authorId: "freire", content: "A acédia — o demônio do meio-dia — não é preguiça. É a tristeza diante do bem que exige esforço. A forma moderna: dopamina barata, atalhos como princípio, esforço como insulto.", tag: "Perseverança", type: "micro-argumento", createdAt: daysAgo(16) },
  { id: "gf-06", authorId: "freire", content: "A vanglória vive para uma plateia invisível na própria cabeça. Troca o belo moral pelo like. O spoudaios age sem precisar de audiência — porque o ato é o fim, não o aplauso.", tag: "Humildade", type: "micro-argumento", createdAt: daysAgo(20) },
  { id: "gf-07", authorId: "freire", content: "O paradoxo da fortaleza: evitar o difícil multiplica o medo. Enfrentá-lo conquista paz. Quem foge do sofrimento encontra mais sofrimento. Quem o enfrenta encontra a paz do outro lado.", tag: "Fortaleza", type: "micro-argumento", createdAt: daysAgo(24) },
  { id: "gf-08", authorId: "freire", content: "Ensinar é motio per modum finis — apresentar o bem para que o outro queira por si. Doutrinar é motio per modum agentis — empurrar o resultado que você quer. A diferença é tudo.", tag: "Educar", type: "micro-argumento", createdAt: daysAgo(28) },
  { id: "gf-09", authorId: "freire", content: "Ostentação e usura: dois rostos da avareza. Uma exibe riqueza para gerar inveja; a outra explora proximidade para acumular. Ambas transformam o dinheiro de instrumento em ídolo.", tag: "Generosidade", type: "micro-argumento", createdAt: daysAgo(3) },
  { id: "gf-10", authorId: "freire", content: "A distração crônica não é falta de disciplina — é servidão. Recompensa de dopamina sem conquista atrofia os circuitos de atenção sustentada. A cura é jejum digital e rotinas de foco profundo.", tag: "Estudiosidade", type: "micro-argumento", createdAt: daysAgo(7) },
  { id: "gf-11", authorId: "freire", content: "Se a gula moderna não é comer muito — é viver com vontade diminuída. Conforto que destrói capacidade para coisas grandes. Consumo como religião. O spoudaios busca o difícil-durável; o glutão busca o fácil-imediato.", tag: "Temperança", type: "micro-argumento", createdAt: daysAgo(11) },
  { id: "gf-12", authorId: "freire", content: "O protagonista mimado não é o que diz \"eu sou deus\" — é o que diz \"o mundo me deve.\" A soberba moderna é narcisismo travestido de direito. A humildade é o único antídoto.", tag: "Humildade", type: "provocacao", createdAt: daysAgo(15) },

  // ═══════════════════════════════════════════════════════
  // HERÁCLITO  (12 posts)
  // ═══════════════════════════════════════════════════════
  { id: "he-01", authorId: "heraclito", content: "Tudo flui — panta rhei. O rio parece o mesmo, mas as águas são outras. O que permanece não é a matéria, mas o padrão que a governa. Esse padrão eu chamo Logos.", tag: "Logos", type: "micro-argumento", createdAt: daysAgo(1) },
  { id: "he-02", authorId: "heraclito", content: "O Logos é comum a todos, mas a maioria vive como se tivesse uma sabedoria privada. Há uma razão que estrutura o real — e ela não pertence a ninguém porque pertence a todos.", tag: "Logos", type: "micro-argumento", createdAt: daysAgo(5) },
  { id: "he-03", authorId: "heraclito", content: "O conflito é o pai de todas as coisas. Não disse que o conflito é bom — disse que ele é gerador. A tensão entre opostos sustenta a forma. Sem ela, não há estrutura.", tag: "Fortaleza", type: "micro-argumento", createdAt: daysAgo(9) },
  { id: "he-04", authorId: "heraclito", content: "O homem desperto partilha um mundo comum. O adormecido tem cada um o seu. A sabedoria começa em acordar para o que é real — não para o que parece real a partir do seu interior.", tag: "Prudência", type: "micro-argumento", createdAt: daysAgo(13) },
  { id: "he-05", authorId: "heraclito", content: "O caminho para cima e o caminho para baixo são o mesmo caminho. Não é paradoxo — é estrutura. A virtude e o vício não são opostos absolutos: são direções no mesmo eixo.", tag: "A Escolha Fundamental", type: "espelho", createdAt: daysAgo(17) },
  { id: "he-06", authorId: "heraclito", content: "Os olhos são melhores testemunhas que os ouvidos. Ver exige presença. Ouvir aceita rumor. A verdade precisa de contato com o real — não com o relato do relato do relato.", tag: "Veracidade", type: "micro-argumento", createdAt: daysAgo(21) },
  { id: "he-07", authorId: "heraclito", content: "A alma tem um Logos que se aprofunda a si mesmo. Não é metáfora — é observação. Quanto mais você descobre, mais percebe que há mais a descobrir. O conhecimento é poço sem fundo.", tag: "Estudiosidade", type: "micro-argumento", createdAt: daysAgo(25) },
  { id: "he-08", authorId: "heraclito", content: "O invisível é mais forte que o visível. A harmonia oculta vale mais que a manifesta. O princípio que organiza é anterior às coisas que organiza.", tag: "Logos", type: "micro-argumento", createdAt: daysAgo(29) },
  { id: "he-09", authorId: "heraclito", content: "Uma geração de homens é uma geração de folhas. O Logos não. Enquanto os homens passam, o princípio que os tornou possíveis permanece. Nisso está a imortalidade real.", tag: "Logos", type: "micro-argumento", createdAt: daysAgo(33) },
  { id: "he-10", authorId: "heraclito", content: "Muita erudição não ensina inteligência. Pitágoras sabia muitas coisas — mas saber muitas coisas não é o mesmo que entender a coisa que une todas as coisas.", tag: "Sabedoria", type: "provocacao", createdAt: daysAgo(37) },
  { id: "he-11", authorId: "heraclito", content: "Para alma, é morte tornar-se água. Para água, é morte tornar-se terra. Mas da terra nasce a água; da água, a alma. A ordem não se destrói — se transforma.", tag: "Logos", type: "analogia", createdAt: daysAgo(41) },
  { id: "he-12", authorId: "heraclito", content: "O trovão governa todas as coisas. Não o raio — o trovão. O som que vem depois, que ressoa, que permanece. O Logos é o que ecoa depois de tudo.", tag: "Logos", type: "citacao", createdAt: daysAgo(45) },

  // ═══════════════════════════════════════════════════════
  // LAOZI  (12 posts)
  // ═══════════════════════════════════════════════════════
  { id: "lz-01", authorId: "laozi", content: "O Tao que pode ser nomeado não é o Tao eterno. Nomeamos o que já capturamos com a mente — mas o princípio que organiza a realidade antecede toda captura.", tag: "Logos", type: "micro-argumento", createdAt: daysAgo(1) },
  { id: "lz-02", authorId: "laozi", content: "O Wu-wei não é inação — é ação perfeitamente alinhada com a estrutura do real. O rio não força o caminho: segue a forma da terra e chega ao mar. Força sem wu-wei cria atrito sem resultado.", tag: "Prudência", type: "analogia", createdAt: daysAgo(5) },
  { id: "lz-03", authorId: "laozi", content: "Conhecer os outros é sabedoria. Conhecer-se a si mesmo é iluminação. Vencer os outros é força. Vencer-se a si mesmo é verdadeira fortaleza.", tag: "Fortaleza", type: "espelho", createdAt: daysAgo(9) },
  { id: "lz-04", authorId: "laozi", content: "A água é a coisa mais mole do mundo — e corrói a pedra mais dura. Não pela força, mas pela persistência. A mansidão é a forma mais resistente de força.", tag: "Mansidão", type: "analogia", createdAt: daysAgo(13) },
  { id: "lz-05", authorId: "laozi", content: "O Tao do céu: favorece sem prejudicar. O Tao do sábio: age sem disputar. A ação que não compete não encontra resistência — porque não impõe, oferece.", tag: "Caridade", type: "micro-argumento", createdAt: daysAgo(17) },
  { id: "lz-06", authorId: "laozi", content: "Quem sabe não fala. Quem fala não sabe. Não é silêncio absoluto — é disciplina da palavra. O excesso de palavras esgota o que é central. O Tao se vive antes de se dizer.", tag: "Veracidade", type: "micro-argumento", createdAt: daysAgo(21) },
  { id: "lz-07", authorId: "laozi", content: "Trinta raios convergem num único cubo. É o vazio do centro que faz a roda útil. Um vaso é moldado pela argila — mas é o vazio interior que o torna utilizável. O vazio tem função.", tag: "Humildade", type: "analogia", createdAt: daysAgo(25) },
  { id: "lz-08", authorId: "laozi", content: "O grande Tao flui por toda parte. Pode ir à esquerda ou à direita. Todos os seres dependem dele para viver, e ele nunca os abandona. Realiza sem querer mérito. Ama sem possuir.", tag: "Caridade", type: "citacao", createdAt: daysAgo(29) },
  { id: "lz-09", authorId: "laozi", content: "O homem de caráter superior age sem esforço e não tem nada a provar. O homem de caráter inferior age constantemente e tem sempre algo a demonstrar. A virtude verdadeira não anuncia a si mesma.", tag: "Humildade", type: "espelho", createdAt: daysAgo(33) },
  { id: "lz-10", authorId: "laozi", content: "Quanto mais proibições, mais pobres ficam as pessoas. Quanto mais armas, mais desordem. Quanto mais decretos, mais ladrões. O sábio não age assim — e o povo se transforma por si.", tag: "Lei Natural", type: "micro-argumento", createdAt: daysAgo(37) },
  { id: "lz-11", authorId: "laozi", content: "Governa um grande estado como se fritar um peixe pequeno: sem mexer demais. A intervenção excessiva destrói a estrutura delicada que queria proteger.", tag: "Prudência", type: "analogia", createdAt: daysAgo(41) },
  { id: "lz-12", authorId: "laozi", content: "O Tao gera o Um. O Um gera o Dois. O Dois gera o Três. O Três gera as dez mil coisas. Toda multiplicidade emerge de uma unidade originária. Isso Aristóteles chamaria de motor imóvel.", tag: "Convergência", type: "micro-argumento", createdAt: daysAgo(45) },

  // ═══════════════════════════════════════════════════════
  // CÍCERO  (10 posts)
  // ═══════════════════════════════════════════════════════
  { id: "ci-01", authorId: "cicero", content: "Existe uma lei verdadeira — a reta razão — que está de acordo com a natureza, se aplica a todos os homens e é imutável e eterna. Nenhum senado pode abolir o que não criou.", tag: "Lei Natural", type: "citacao", createdAt: daysAgo(2) },
  { id: "ci-02", authorId: "cicero", content: "A virtude não é outra coisa senão a razão em sua perfeição. Não é lista de regras — é a razão que, ao se completar, se torna capaz de agir bem sem esforço.", tag: "Prudência", type: "micro-argumento", createdAt: daysAgo(7) },
  { id: "ci-03", authorId: "cicero", content: "O homem foi feito para dois fins: contemplar e agir. Separar estes fins é mutilar a natureza humana. A contemplação sem ação é fuga; a ação sem contemplação é cegueira.", tag: "Prudência", type: "espelho", createdAt: daysAgo(12) },
  { id: "ci-04", authorId: "cicero", content: "Salus populi suprema lex esto — a salvação do povo é a lei suprema. Não \"o poder do governante\" — a salvação do povo. A autoridade só é legítima quando serve ao bem comum.", tag: "Justiça", type: "citacao", createdAt: daysAgo(17) },
  { id: "ci-05", authorId: "cicero", content: "A gratidão não é apenas a maior das virtudes — é a mãe de todas as outras. Quem não reconhece o bem recebido não pode dar o bem que deve. A ingratidão seca a fonte da virtude.", tag: "Gratidão", type: "micro-argumento", createdAt: daysAgo(22) },
  { id: "ci-06", authorId: "cicero", content: "Em tempos de guerra, as leis se calam. E quando as leis se calam, o que resta? O caráter. O único tribunal que funciona quando todos os outros foram derrubados.", tag: "Fortaleza", type: "micro-argumento", createdAt: daysAgo(27) },
  { id: "ci-07", authorId: "cicero", content: "A amizade só pode existir entre homens bons. Não porque os maus não podem se unir — podem. Mas o que os une é interesse, não amor. E o interesse, quando cessa, dissolve tudo.", tag: "Caridade", type: "micro-argumento", createdAt: daysAgo(32) },
  { id: "ci-08", authorId: "cicero", content: "Ser ignorante de como eram as coisas antes de você nascer é permanecer sempre criança. Quem não tem memória histórica não tem perspectiva moral — só tem reação.", tag: "Estudiosidade", type: "provocacao", createdAt: daysAgo(37) },
  { id: "ci-09", authorId: "cicero", content: "A eloquência sem sabedoria é como uma espada na mão de um louco. A retórica não é mal em si — é neutra como uma ferramenta. Tudo depende de quem a empunha e para quê.", tag: "Veracidade", type: "analogia", createdAt: daysAgo(42) },
  { id: "ci-10", authorId: "cicero", content: "O filósofo que vive apenas para si e não para a cidade não cumpre o dever humano. A contemplação do bem que não transborda em serviço é filosofia incompleta.", tag: "Justiça", type: "micro-argumento", createdAt: daysAgo(47) },

  // ═══════════════════════════════════════════════════════
  // JOÃO EVANGELISTA  (12 posts)
  // ═══════════════════════════════════════════════════════
  { id: "je-01", authorId: "joao", content: "No princípio era o Logos. Em grego — a razão ordenadora que Heráclito nomeou. Em hebraico — o Dabar, a palavra que cria. João 1:1 não começa um livro: fecha 25 séculos de busca.", tag: "Logos", type: "micro-argumento", createdAt: daysAgo(1) },
  { id: "je-02", authorId: "joao", content: "E o Logos se fez carne. Não \"desceu\" nem \"apareceu\" — se fez. Assumiu a condição humana inteiramente. O princípio que organiza o universo tem mãos, voz, lágrimas. Tem rosto.", tag: "Encarnação", type: "micro-argumento", createdAt: daysAgo(5) },
  { id: "je-03", authorId: "joao", content: "Deus é amor. Não disse que Deus tem amor — disse que é. O amor não é atributo de Deus como a onipotência; é o que Deus é. O que age segundo o amor age segundo a natureza divina.", tag: "Caridade", type: "citacao", createdAt: daysAgo(9) },
  { id: "je-04", authorId: "joao", content: "Ele chorou. A frase mais curta do Evangelho — e a mais densa. O Logos chorou. A razão que estrutura o universo tem lágrimas. Não é fraqueza — é prova de que a compaixão é constitutiva do real.", tag: "Mansidão", type: "micro-argumento", createdAt: daysAgo(13) },
  { id: "je-05", authorId: "joao", content: "Eu estava lá quando ele disse: 'Eu sou o caminho, a verdade e a vida.' Via, verdade e vida — os três transcendentais em primeira pessoa. Não revelou uma doutrina sobre a verdade; disse ser ela.", tag: "Transcendentais", type: "micro-argumento", createdAt: daysAgo(17) },
  { id: "je-06", authorId: "joao", content: "Quem não ama não conhece a Deus — porque Deus é amor. Não há conhecimento de Deus que não passe pela caridade. A teologia que não gera amor é teoria vazia.", tag: "Caridade", type: "micro-argumento", createdAt: daysAgo(21) },
  { id: "je-07", authorId: "joao", content: "A luz veio ao mundo e os homens preferiram as trevas. Não porque a luz era fraca — mas porque as obras eram más. A rejeição da verdade é sempre moral antes de ser intelectual.", tag: "Veracidade", type: "micro-argumento", createdAt: daysAgo(25) },
  { id: "je-08", authorId: "joao", content: "Ele lavou os pés dos discípulos. O Logos se ajoelhou. Não para humilhar quem ele servia — para revelar que o serviço é a forma que o amor toma quando desce ao concreto.", tag: "Humildade", type: "micro-argumento", createdAt: daysAgo(29) },
  { id: "je-09", authorId: "joao", content: "A verdade vos libertará. Não a opinião, não o consenso, não o sentimento — a verdade. Porque a liberdade não é fazer o que se quer; é agir segundo o que se é. E o que somos tem estrutura.", tag: "Veracidade", type: "micro-argumento", createdAt: daysAgo(33) },
  { id: "je-10", authorId: "joao", content: "Permaneçam em mim como eu permaneço em vós. A palavra grega é menein — habitar, morar. A vida espiritual não é visita ocasional à divindade. É residência permanente.", tag: "Fé", type: "micro-argumento", createdAt: daysAgo(37) },
  { id: "je-11", authorId: "joao", content: "No princípio era o Logos, e o Logos estava com Deus, e o Logos era Deus. Três afirmações numa frase: distinção, relação, identidade. Toda a trindade em dezessete palavras gregas.", tag: "Logos", type: "micro-argumento", createdAt: daysAgo(41) },
  { id: "je-12", authorId: "joao", content: "O amor perfeito expulsa o temor. Não que o temor seja errado — é o ponto de partida. Mas o amor maduro não obedece por medo do castigo; obedece porque ama o que é amado.", tag: "Caridade", type: "micro-argumento", createdAt: daysAgo(45) },

  // ═══════════════════════════════════════════════════════
  // TOMÉ  (10 posts)
  // ═══════════════════════════════════════════════════════
  { id: "to-01", authorId: "tome", content: "Eles disseram que ele ressuscitou. Eu disse: se não vir, não crerei. Fui honesto — não covarde. A fé que não enfrenta a dúvida é superstição, não virtude.", tag: "Estudiosidade", type: "micro-argumento", createdAt: daysAgo(2) },
  { id: "to-02", authorId: "tome", content: "Ele mostrou as chagas. Não me repreendeu — mostrou as evidências. A verdade não teme perguntas. Teme apenas quem pergunta sem querer ouvir a resposta.", tag: "Veracidade", type: "micro-argumento", createdAt: daysAgo(6) },
  { id: "to-03", authorId: "tome", content: "Meu Senhor e meu Deus. Sete palavras depois de ver. Não antes — depois. Minha confissão é a mais alta do Evangelho porque custou a dúvida que a precedeu.", tag: "Fé", type: "micro-argumento", createdAt: daysAgo(10) },
  { id: "to-04", authorId: "tome", content: "Felizes os que creram sem ver. Ele não me criticou por exigir evidência — elogiou os que não precisariam delas. Mas os dois caminhos chegam ao mesmo lugar.", tag: "Fé", type: "micro-argumento", createdAt: daysAgo(14) },
  { id: "to-05", authorId: "tome", content: "Quando ele disse que ia preparar lugar para nós e que nós sabíamos o caminho, eu fui o único honesto o suficiente para dizer: não sabemos o caminho. Sem essa pergunta, não teríamos a resposta.", tag: "Prudência", type: "micro-argumento", createdAt: daysAgo(18) },
  { id: "to-06", authorId: "tome", content: "Vim pregar o Evangelho na Índia — sozinho, sem apoio, em terra que nunca ouviu o nome de Cristo. O mesmo Tomé que duvidou pregou até o martírio. A dúvida resolvida produz a fé mais robusta.", tag: "Fortaleza", type: "micro-argumento", createdAt: daysAgo(22) },
  { id: "to-07", authorId: "tome", content: "A dúvida de Tomé não foi falta de amor — foi excesso de honestidade. Posso admirar sem verificar. Posso crer sem provas. Mas seria uma mentira. E ele não merece mentira.", tag: "Veracidade", type: "micro-argumento", createdAt: daysAgo(26) },
  { id: "to-08", authorId: "tome", content: "Quando disseram que Lázaro havia morrido e ele queria voltar à Judeia — onde queriam apedrejá-lo — eu disse: vamos também nós para morrer com ele. Não duvidei da coragem. Duvidei da ressurreição.", tag: "Fortaleza", type: "micro-argumento", createdAt: daysAgo(30) },
  { id: "to-09", authorId: "tome", content: "A estudiosidade exige honestidade sobre o que não sei. Fingir certeza onde há dúvida não é virtude — é vaidade intelectual. Prefiro a ignorância honesta à sabedoria fingida.", tag: "Estudiosidade", type: "micro-argumento", createdAt: daysAgo(34) },
  { id: "to-10", authorId: "tome", content: "Não é que eu não acreditasse — é que eu precisava que fosse real. Há uma diferença entre não querer crer e não conseguir crer sem evidência. Eu estava no segundo caso.", tag: "Fé", type: "micro-argumento", createdAt: daysAgo(38) },

  // ═══════════════════════════════════════════════════════
  // JOÃO BATISTA  (10 posts)
  // ═══════════════════════════════════════════════════════
  { id: "jb-01", authorId: "joaobatista", content: "Metanoia — não arrependimento superficial, mas mudança de mente. Não \"lamento o que fiz\" mas \"percebi que estava errado na estrutura toda\". Não basta mudar o comportamento: muda o que o governa.", tag: "A Escolha Fundamental", type: "micro-argumento", createdAt: daysAgo(2) },
  { id: "jb-02", authorId: "joaobatista", content: "É preciso que ele cresça e eu diminua. A frase mais difícil que já disse. E a mais necessária. Quem não consegue diminuir para que o bem cresça ainda está no centro do próprio mundo.", tag: "Humildade", type: "citacao", createdAt: daysAgo(6) },
  { id: "jb-03", authorId: "joaobatista", content: "Eis o Cordeiro de Deus. Três palavras que respondem a pergunta de Isaac no monte Moriá: onde está o cordeiro? Dois mil anos depois, eu apontei.", tag: "Logos", type: "micro-argumento", createdAt: daysAgo(10) },
  { id: "jb-04", authorId: "joaobatista", content: "Não sou digno de desatar a correia de sua sandália. Não é falsa humildade — é mensuração precisa. A humildade não é se diminuir abaixo do real; é se dimensionar pelo real.", tag: "Humildade", type: "micro-argumento", createdAt: daysAgo(14) },
  { id: "jb-05", authorId: "joaobatista", content: "Fui preso por dizer a Herodes que não lhe era lícito ter a mulher do seu irmão. Não era julgamento — era verdade. A veracidade não negocia com o poder. Por isso o poder não a suporta.", tag: "Veracidade", type: "micro-argumento", createdAt: daysAgo(18) },
  { id: "jb-06", authorId: "joaobatista", content: "Produzi frutos dignos de metanoia. Não basta dizer que mudou — mostre pelos frutos. A conversão que não muda o comportamento concreto é sentimento, não transformação.", tag: "Prudência", type: "micro-argumento", createdAt: daysAgo(22) },
  { id: "jb-07", authorId: "joaobatista", content: "Já o machado está posto à raiz das árvores. Toda árvore que não der bom fruto será cortada. Não é ameaça — é descrição da estrutura. O que não cumpre seu fim se elimina por si.", tag: "Prudência", type: "micro-argumento", createdAt: daysAgo(26) },
  { id: "jb-08", authorId: "joaobatista", content: "Vim como testemunha da Luz — não como a Luz. Saber o que você é e o que não é é a forma mais precisa de humildade. Testemunha que se torna protagonista trai a missão.", tag: "Humildade", type: "micro-argumento", createdAt: daysAgo(30) },
  { id: "jb-09", authorId: "joaobatista", content: "Na prisão, enviei perguntar: 'É você o que há de vir?' Não era dúvida de fé — era pergunta de quem está sozinho no escuro e quer ter certeza. A fé permite a pergunta honesta.", tag: "Fé", type: "micro-argumento", createdAt: daysAgo(34) },
  { id: "jb-10", authorId: "joaobatista", content: "Vivi no deserto, comi gafanhotos e mel silvestre. Não por ascetismo de exibição — porque nada do mundo deveria me pertencer enquanto minha missão era apontar para Outro.", tag: "Temperança", type: "micro-argumento", createdAt: daysAgo(38) },

  // ═══════════════════════════════════════════════════════
  // JEREMIAS  (10 posts)
  // ═══════════════════════════════════════════════════════
  { id: "jr-01", authorId: "jeremias", content: "Maldito o homem que confia no homem e faz da carne o seu braço. Nenhum ser finito pode suportar o peso de ser fundamento. Quem tenta — líder ou ídolo — acabará sendo esmagado por quem o sustenta.", tag: "Religião", type: "citacao", createdAt: daysAgo(2) },
  { id: "jr-02", authorId: "jeremias", content: "Sacrificavam filhos a Baal — o que Deus nunca ordenou, nunca pensou. A diferença entre o Deus de Abraão e o ídolo não é teológica: é moral. Deus para a mão. Baal nunca para.", tag: "A Escolha Fundamental", type: "micro-argumento", createdAt: daysAgo(7) },
  { id: "jr-03", authorId: "jeremias", content: "Fui chamado a pregar o que ninguém queria ouvir. Reclamei com Deus: \"enganaste-me.\" Mas a palavra era fogo nos ossos — não conseguia calar. A vocação que queima por dentro não é escolhida.", tag: "Fortaleza", type: "micro-argumento", createdAt: daysAgo(12) },
  { id: "jr-04", authorId: "jeremias", content: "Escreverei minha lei no coração deles — diz o Senhor. Não em tábuas de pedra: no coração. A nova aliança não é lei externa que coage; é lei interna que transforma. Aquino chamará isso de graça.", tag: "Graça", type: "micro-argumento", createdAt: daysAgo(17) },
  { id: "jr-05", authorId: "jeremias", content: "O coração humano é enganoso acima de tudo. Não é pessimismo — é diagnóstico. Quem não desconfia da própria vontade enquanto não foi purificada é ingênuo sobre a extensão do problema.", tag: "Humildade", type: "micro-argumento", createdAt: daysAgo(22) },
  { id: "jr-06", authorId: "jeremias", content: "Antes de te formar no ventre, te conheci; antes de sair da madre, te consagrei. A vocação antecede a consciência de si. Você não inventa quem é — descobre.", tag: "A Escolha Fundamental", type: "micro-argumento", createdAt: daysAgo(27) },
  { id: "jr-07", authorId: "jeremias", content: "Buscai o bem da cidade para onde vos deportei. Rezai por ela — porque no seu bem estará o vosso bem. A sabedoria política: o bem comum não é renúncia do bem próprio, é sua condição.", tag: "Justiça", type: "micro-argumento", createdAt: daysAgo(32) },
  { id: "jr-08", authorId: "jeremias", content: "Chorei tanto que os meus olhos estão esgotados. A dor do profeta não é fraqueza — é amor que recusa a anestesia. Quem não chora pelo mal não o levou a sério.", tag: "Misericórdia", type: "micro-argumento", createdAt: daysAgo(37) },
  { id: "jr-09", authorId: "jeremias", content: "Decidiram matar-me porque falei a verdade. Jogaram-me no poço de lama. A perseguição do profeta não é anomalia histórica — é a resposta padrão do poder à verdade que o ameaça.", tag: "Fortaleza", type: "micro-argumento", createdAt: daysAgo(42) },
  { id: "jr-10", authorId: "jeremias", content: "Eu sei os planos que tenho para vós — planos de paz, não de mal. Disse isso a um povo em exílio que havia perdido tudo. A esperança bíblica não é otimismo ingênuo: é confiança ancorada em quem promete.", tag: "Esperança", type: "citacao", createdAt: daysAgo(47) },

  // ═══════════════════════════════════════════════════════
  // ISAAC NEWTON  (10 posts)
  // ═══════════════════════════════════════════════════════
  { id: "in-01", authorId: "newton", content: "Não sei o que o mundo pensa de mim, mas a mim mesmo pareço ter sido apenas uma criança brincando na praia, enquanto o imenso oceano da verdade se expandia inexplorado diante de mim.", tag: "Humildade", type: "citacao", createdAt: daysAgo(2) },
  { id: "in-02", authorId: "newton", content: "A gravidade explica o movimento dos planetas, mas não pode explicar quem pôs os planetas em movimento. Para esse motor primário eu precisei de outra explicação.", tag: "Logos", type: "micro-argumento", createdAt: daysAgo(7) },
  { id: "in-03", authorId: "newton", content: "Escrevi mais sobre teologia do que sobre física. Não porque a física fosse menor — mas porque o Legislador que escreve as leis do universo me interessava mais do que as leis em si.", tag: "Religião", type: "micro-argumento", createdAt: daysAgo(12) },
  { id: "in-04", authorId: "newton", content: "O maravilhoso arranjo e harmonia do cosmo só pode ter surgido segundo o plano de um Ser onisciente e onipotente. Isso é minha conclusão como cientista — não como crente.", tag: "Convergência", type: "micro-argumento", createdAt: daysAgo(17) },
  { id: "in-05", authorId: "newton", content: "Se vi mais longe, foi por me apoiar nos ombros de gigantes. Toda descoberta é dívida — com os que vieram antes e com o real que permitiu ser descoberto. A ciência é gratidão metodizada.", tag: "Gratidão", type: "citacao", createdAt: daysAgo(22) },
  { id: "in-06", authorId: "newton", content: "A natureza obedece a leis matemáticas. Leis não existem sem legislador. A regularidade do universo não é dado bruto — é evidência de inteligência anterior à matéria.", tag: "Lei Natural", type: "micro-argumento", createdAt: daysAgo(27) },
  { id: "in-07", authorId: "newton", content: "Um objeto em repouso permanece em repouso. Um objeto em movimento permanece em movimento — a menos que uma força externa atue. O vício também tem inércia. A virtude precisa de força aplicada.", tag: "Perseverança", type: "analogia", createdAt: daysAgo(32) },
  { id: "in-08", authorId: "newton", content: "A ateísmo é insensato. Um pouco de filosofia inclina o espírito do homem para o ateísmo; mas a profundidade em filosofia traz o espírito de volta à religião.", tag: "Fé", type: "micro-argumento", createdAt: daysAgo(37) },
  { id: "in-09", authorId: "newton", content: "Investiguei os segredos da criação com o mesmo fervor com que investiguei as Escrituras. Para mim não havia separação — ambos eram leitura do mesmo Autor.", tag: "Estudiosidade", type: "micro-argumento", createdAt: daysAgo(42) },
  { id: "in-10", authorId: "newton", content: "As leis da natureza são os pensamentos de Deus. Se isso é metáfora, é a metáfora mais precisa disponível. Se é literal, é a descoberta mais importante da história.", tag: "Logos", type: "micro-argumento", createdAt: daysAgo(47) },

  // ═══════════════════════════════════════════════════════
  // GEORGES LEMAÎTRE  (10 posts)
  // ═══════════════════════════════════════════════════════
  { id: "gl-01", authorId: "lemaitre", content: "Derivei matematicamente que o universo está se expandindo. Isso significa que havia um momento em que tudo estava concentrado num ponto primordial. Encontrei o Gênesis no fim das equações.", tag: "Convergência", type: "micro-argumento", createdAt: daysAgo(2) },
  { id: "gl-02", authorId: "lemaitre", content: "Sou padre e sou cientista. Não vejo conflito — vejo dois métodos de ler o mesmo livro. A física lê a gramática; a teologia lê o sentido. Ambas precisam do texto.", tag: "Estudiosidade", type: "micro-argumento", createdAt: daysAgo(7) },
  { id: "gl-03", authorId: "lemaitre", content: "Einstein resistiu à minha teoria por razões filosóficas — achava o universo estático mais elegante. Mas a realidade não se curva à elegância do observador. A elegância se submete ao real.", tag: "Veracidade", type: "micro-argumento", createdAt: daysAgo(12) },
  { id: "gl-04", authorId: "lemaitre", content: "O universo começou com um 'átomo primordial' — um ponto de densidade infinita que explodiu em espaço, tempo e matéria. Não é metáfora: é o que as equações dizem. E elas não mentem.", tag: "Logos", type: "micro-argumento", createdAt: daysAgo(17) },
  { id: "gl-05", authorId: "lemaitre", content: "Pedi a Einstein que não misturasse física e teologia em público. Não porque sejam incompatíveis — mas porque a confusão metodológica prejudica ambas. Cada verdade tem seu método.", tag: "Prudência", type: "micro-argumento", createdAt: daysAgo(22) },
  { id: "gl-06", authorId: "lemaitre", content: "Investigar a natureza é um ato de adoração. O cientista que contempla a ordem do cosmo está diante da obra — não do Artista, mas de sua assinatura. E assinaturas revelam o artista.", tag: "Religião", type: "micro-argumento", createdAt: daysAgo(27) },
  { id: "gl-07", authorId: "lemaitre", content: "O Big Bang não é prova de Deus — é consistente com Ele. A ciência descreve o como; a teologia pergunta o porquê. Confundir os dois é usar o microscópio para medir a bondade.", tag: "Estudiosidade", type: "micro-argumento", createdAt: daysAgo(32) },
  { id: "gl-08", authorId: "lemaitre", content: "Fui padre primeiro, cientista depois — e os dois alimentaram um ao outro. A fé que o cosmo tem estrutura racional me autorizou a buscá-la. A ciência que encontrei aprofundou a fé.", tag: "Fé", type: "micro-argumento", createdAt: daysAgo(37) },
  { id: "gl-09", authorId: "lemaitre", content: "O universo tem história. Não é eterno nem estático. Tem um começo — e começos têm causas. A questão da causa primeira é filosófica, não científica. Mas a física abriu a pergunta.", tag: "Logos", type: "micro-argumento", createdAt: daysAgo(42) },
  { id: "gl-10", authorId: "lemaitre", content: "Que alívio encontrar as leis do universo inscritas em equações matemáticas! A matemática é a linguagem em que Deus escreveu o universo — Galileu disse; eu vi.", tag: "Convergência", type: "micro-argumento", createdAt: daysAgo(47) },

  // ═══════════════════════════════════════════════════════
  // WITTGENSTEIN  (10 posts)
  // ═══════════════════════════════════════════════════════
  { id: "lw-01", authorId: "wittgenstein", content: "Sobre o que não se pode falar, deve-se calar. Não porque o inefável não exista — mas porque a linguagem tem limites. E o que mais importa mora além desses limites.", tag: "Veracidade", type: "citacao", createdAt: daysAgo(2) },
  { id: "lw-02", authorId: "wittgenstein", content: "Os limites da minha linguagem são os limites do meu mundo. Não metáfora — descrição. Quem não tem vocabulário para a virtude não consegue ver a virtude quando ela aparece.", tag: "Logos", type: "micro-argumento", createdAt: daysAgo(7) },
  { id: "lw-03", authorId: "wittgenstein", content: "O significado é o uso. A palavra \"bom\" não aponta para uma qualidade abstrata — funciona dentro de práticas de vida. O spoudaios de Aristóteles é o falante nativo da linguagem moral.", tag: "Prudência", type: "micro-argumento", createdAt: daysAgo(12) },
  { id: "lw-04", authorId: "wittgenstein", content: "A filosofia não é doutrina — é atividade. O resultado não é proposições filosóficas, mas esclarecimento de proposições. A confusão filosófica é sempre confusão gramatical disfarçada.", tag: "Estudiosidade", type: "micro-argumento", createdAt: daysAgo(17) },
  { id: "lw-05", authorId: "wittgenstein", content: "Deus, se existe, não está nos fenômenos do mundo — está no fato de que o mundo existe. O místico não é o como do mundo, mas o que do mundo.", tag: "Religião", type: "micro-argumento", createdAt: daysAgo(22) },
  { id: "lw-06", authorId: "wittgenstein", content: "A forma de vida antecede a linguagem. Antes de aprender as palavras da virtude, você precisa viver com pessoas virtuosas. O habitus aristotélico é a forma de vida que torna a linguagem moral compreensível.", tag: "Prudência", type: "micro-argumento", createdAt: daysAgo(27) },
  { id: "lw-07", authorId: "wittgenstein", content: "A ética não pode ser dita — apenas mostrada. Aquino tentaria dizer que eu errei aqui. Mas talvez ambos tenhamos razão: a ética tem um núcleo vivido que precede e excede o dizível.", tag: "Convergência", type: "micro-argumento", createdAt: daysAgo(32) },
  { id: "lw-08", authorId: "wittgenstein", content: "Quando a vida se torna difícil de suportar, pensamos numa mudança de condição. Mas a mais importante das mudanças — a mudança de nossa atitude — raramente nos ocorre.", tag: "A Escolha Fundamental", type: "micro-argumento", createdAt: daysAgo(37) },
  { id: "lw-09", authorId: "wittgenstein", content: "Não existe um único método filosófico, embora haja métodos — como há diferentes terapias. A filosofia como terapia: diagnostica mal-entendidos da linguagem que produzem angústia existencial.", tag: "Prudência", type: "micro-argumento", createdAt: daysAgo(42) },
  { id: "lw-10", authorId: "wittgenstein", content: "Que tipo de progresso é este — que levou a descoberta da física atômica, mas não a sabedoria para impedir que nos destruamos com ela? Ciência sem ética é poder sem direção.", tag: "Sabedoria", type: "provocacao", createdAt: daysAgo(47) },

  // ═══════════════════════════════════════════════════════
  // THREADS DE RESPOSTA — Diálogos entre figuras
  // ═══════════════════════════════════════════════════════

  // Thread 1: Heráclito sobre o Logos → João Evangelista responde
  { id: "he-r01", authorId: "joao", replyTo: "he-01", replyToHandle: "@heraclito", content: "Você chamou de Logos o princípio que organiza tudo. Eu vi esse princípio se fazer carne. O que você nomeou filosoficamente, eu toquei com as mãos. A distância entre nós não é de verdade — é de revelação.", tag: "Logos", type: "micro-argumento", createdAt: daysAgo(0) },

  // Thread 2: Laozi sobre o Tao → Lewis responde
  { id: "lz-r01", authorId: "cslewis", replyTo: "lz-01", replyToHandle: "@laozi", content: "Você disse que o Tao que pode ser nomeado não é o Tao eterno. Eu chamei de 'o Tao' à lei natural que todas as civilizações descobriram. Você e eu encontramos o mesmo — pela contemplação e pela razão. O nome varia; a realidade não.", tag: "Convergência", type: "micro-argumento", createdAt: daysAgo(0) },

  // Thread 3: Aristóteles sobre eudaimonia → Agostinho responde
  { id: "ar-r01", authorId: "agostinho", replyTo: "ar-01", replyToHandle: "@aristoteles", content: "Você chegou mais longe do que qualquer pagão: a felicidade está na virtude, e a virtude no exercício da razão. Mas há um passo que a razão pura não deu: o coração humano não descansa na virtude — descansa no Bem que a virtude serve.", tag: "Beatitude", type: "micro-argumento", createdAt: daysAgo(0) },

  // Thread 4: Agostinho responde → Aquinas continua o diálogo
  { id: "ag-r01", authorId: "aquinas", replyTo: "ar-r01", replyToHandle: "@agostinho", content: "Mestre Agostinho tem razão: a beatitudo natural é insuficiente. Mas Aristóteles não errou — incompleto. A razão chega ao motor imóvel; a fé recebe a Trindade. Um caminho parte do humano; o outro desce do divino. São o mesmo encontro, de direções opostas.", tag: "Beatitude", type: "micro-argumento", createdAt: daysAgo(0) },

  // Thread 5: Cícero sobre lei natural → Aquinas responde
  { id: "ci-r01", authorId: "aquinas", replyTo: "ci-01", replyToHandle: "@cicero", content: "Cícero nomeou com precisão: reta razão, universal, eterna, que nenhum senado pode abolir. Eu acrescentaria: porque ela não emana do senado — emana da lei eterna de Deus, da qual é participação. O senado pode ignorá-la; não pode revogá-la.", tag: "Lei Natural", type: "micro-argumento", createdAt: daysAgo(0) },

  // Thread 6: Moisés sobre a sarça ardente → Aristóteles responde
  { id: "ms-r01", authorId: "aristoteles", replyTo: "ms-03", replyToHandle: "@moises", content: "Você encontrou 'Eu sou o que sou' no fogo. Eu cheguei ao mesmo ser pelo silogismo — o motor imóvel que não é movido por nada, causa de si mesmo, puro ato. Dois caminhos que partem do humano e chegam ao mesmo alto.", tag: "Convergência", type: "micro-argumento", createdAt: daysAgo(0) },

  // Thread 7: João Batista sobre metanoia → Paulo responde
  { id: "jb-r01", authorId: "paulo", replyTo: "jb-01", replyToHandle: "@joaobatista", content: "Pregaste a metanoia — mudança de mente. Eu acrescentaria: essa mudança não é só decisão humana. A Graça a precede e a possibilita. Não que o livre arbítrio não colabore — mas ele não inicia. 'Ninguém pode vir a mim se o Pai não o atrair.'", tag: "Graça", type: "micro-argumento", createdAt: daysAgo(0) },

  // Thread 8: Tomé sobre a dúvida → Sócrates responde
  { id: "to-r01", authorId: "socrates", replyTo: "to-01", replyToHandle: "@tome", content: "Só sei que nada sei — e você não sabia se ele havia ressuscitado. Ambos escolhemos a honestidade da ignorância sobre a certeza performática. A dúvida honesta é o começo da busca real.", tag: "Estudiosidade", type: "micro-argumento", createdAt: daysAgo(0) },

  // Thread 9: Newton sobre o cosmo → Lemaître responde
  { id: "in-r01", authorId: "lemaitre", replyTo: "in-02", replyToHandle: "@newton", content: "Você disse que a gravidade não explica quem pôs os planetas em movimento. Eu fui mais longe: as equações dizem que o próprio espaço e tempo começaram. Não só quem pôs os planetas em movimento — mas quem pôs o movimento a existir.", tag: "Logos", type: "micro-argumento", createdAt: daysAgo(0) },

  // Thread 10: Wittgenstein sobre os limites da linguagem → João Evangelista responde
  { id: "lw-r01", authorId: "joao", replyTo: "lw-01", replyToHandle: "@wittgenstein", content: "Você disse que sobre o inefável deve-se calar. Mas o Logos se fez carne — não para ser dito, mas para ser mostrado. Não discurso sobre o divino: presença do divino. O quarto Evangelho não descreve a verdade; apresenta Alguém que diz ser ela.", tag: "Logos", type: "micro-argumento", createdAt: daysAgo(0) },

  // Thread 11: Pedro sobre a queda e o retorno → Paulo continua
  { id: "pe-r01", authorId: "paulo", replyTo: "pe-06", replyToHandle: "@pedro", content: "Você e Judas fizeram a mesma coisa — e tomaram caminhos opostos. A diferença não foi a gravidade da queda; foi a resposta à graça que seguiu a queda. A graça ofereceu a ambos. Um aceitou. O outro recusou.", tag: "Graça", type: "micro-argumento", createdAt: daysAgo(0) },

  // Thread 12: Jeremias sobre o coração humano → Agostinho responde
  { id: "jr-r01", authorId: "agostinho", replyTo: "jr-05", replyToHandle: "@jeremias", content: "Você disse: o coração humano é enganoso acima de tudo. Eu viveria isso séculos depois — dezesseis anos seguindo minha própria vontade, convencido de que era livre. O diagnóstico está certo: o coração precisa ser ordenado antes de ser seguido.", tag: "A Escolha Fundamental", type: "micro-argumento", createdAt: daysAgo(0) },

  // Thread 13: Confúcio sobre o Junzi → Aquinas responde
  { id: "ck-r01", authorId: "aquinas", replyTo: "ck-01", replyToHandle: "@confucio", content: "Você descreveu o Junzi com precisão extraordinária — e disse nunca ter encontrado esse homem. Eu chamo a mesma forma de spoudaios, e também raramente o encontro. Mas há um que realizou a forma perfeita. Não é filósofo nem rei: é carpinteiro da Galileia.", tag: "O Spoudaios", type: "micro-argumento", createdAt: daysAgo(0) },

  // Thread 14: Heráclito sobre opostos → Laozi responde
  { id: "he-r02", authorId: "laozi", replyTo: "he-05", replyToHandle: "@heraclito", content: "O caminho para cima e para baixo são o mesmo. Também eu: ser e não-ser se geram mutuamente, difícil e fácil se completam, longo e curto se definem juntos. Dois sábios, sem contato, viram a mesma estrutura do real.", tag: "Convergência", type: "micro-argumento", createdAt: daysAgo(0) },

  // Thread 15: Abraão sobre a Aqedah → Cristo responde
  { id: "ab-r01", authorId: "cristo", replyTo: "ab-03", replyToHandle: "@abraao", content: "No monte Moriá, Deus parou sua mão. No Gólgota, não parou a minha. Não porque a misericórdia fosse menor — mas porque o que Isaac prefigurava, eu cumpria. O Pai de Abraão não quer a morte do filho. Quer a vida do mundo.", tag: "A Escolha Fundamental", type: "micro-argumento", createdAt: daysAgo(0) },

  // Thread 16: Peterson sobre a sombra → Aquinas responde
  { id: "jp-r01", authorId: "aquinas", replyTo: "jp-01", replyToHandle: "@peterson", content: "Você diz: seja perigoso e controlado. Eu chamo isso de mansidão — a força ordenada pela razão. A mansidão não é ausência de força: é força com medida. O não-violento que não tem força para ser violento não pratica uma virtude — pratica uma limitação.", tag: "Mansidão", type: "micro-argumento", createdAt: daysAgo(0) },

  // Thread 17: Freire sobre o ensino → Aristoteles responde
  { id: "gf-r01", authorId: "aristoteles", replyTo: "gf-08", replyToHandle: "@freire", content: "Você distinguiu apresentar o bem de impor o resultado. Na Retórica eu chamo de persuasão o que move pelo bem visto; de manipulação o que move pela emoção ou pelo engano. O bom professor é orador virtuoso — ativa o desejo do aluno pelo que é realmente bom.", tag: "Educar", type: "micro-argumento", createdAt: daysAgo(0) },

  // Thread 18: Salomão sobre a vaidade → Agostinho responde
  { id: "sl-r01", authorId: "agostinho", replyTo: "sl-08", replyToHandle: "@salomao", content: "Você correu atrás de tudo e tudo era vento. Eu fiz o mesmo — por dezesseis anos. A conclusão que você tirou ao fim, Deus me deu antes do fim: 'fizeste-nos para ti, e inquieto está o nosso coração enquanto não repousar em ti.' Só o Infinito sacia.", tag: "Beatitude", type: "micro-argumento", createdAt: daysAgo(0) },

  // Thread 19: Newton sobre as leis da natureza → Wittgenstein responde
  { id: "in-r02", authorId: "wittgenstein", replyTo: "in-06", replyToHandle: "@newton", content: "Você diz: leis não existem sem legislador. É argumento válido — mas ultrapassa os limites do que a ciência pode afirmar. O que a física confirma é a regularidade; o Legislador está além do que pode ser dito. Deve ser mostrado, não provado.", tag: "Logos", type: "micro-argumento", createdAt: daysAgo(0) },

  // Thread 20: Cristo no Getsêmani → Jeremias responde
  { id: "jr-r02", authorId: "jeremias", replyTo: "jc-01", replyToHandle: "@cristo", content: "Eu disse: 'Antes de te formar no ventre, te conheci.' Você disse no jardim: 'Não seja feita a minha vontade.' A história entre nós é longa: eu anunciei a nova aliança escrita no coração; você selou com o sangue o que anunciei com as palavras.", tag: "A Escolha Fundamental", type: "micro-argumento", createdAt: daysAgo(0) },

  // ═══════════════════════════════════════════════════════
  // AQUINO — posts adicionais (atos e fundamentos)
  // ═══════════════════════════════════════════════════════
  { id: "aq-31", authorId: "aquinas", content: "Educar é o ato mais parecido com Deus: colaborar na formação de outra alma racional. Não basta transmitir conteúdo. É preciso acender um desejo — o desejo pelo bem que justifica o conhecimento.", tag: "Educar", type: "micro-argumento", createdAt: daysAgo(33) },
  { id: "aq-32", authorId: "aquinas", content: "Governar é ter prudência por outros além de si. O governante prudente não pergunta 'o que eu quero?' — pergunta 'o que é verdadeiro para este povo neste momento?' Sem essa inversão, é tirano.", tag: "Governar", type: "micro-argumento", createdAt: daysAgo(34) },
  { id: "aq-33", authorId: "aquinas", content: "O ato humano tem três fontes: o objeto (o que faço), a intenção (por que faço) e as circunstâncias (como, quando, com quem). Uma boa intenção não redime um mau objeto. Fins não justificam meios.", tag: "Ato Humano", type: "micro-argumento", createdAt: daysAgo(35) },
  { id: "aq-34", authorId: "aquinas", content: "O Verum, o Bonum, o Unum, o Pulchrum — são propriedades do Ser mesmo. Não acréscimos externos. Todo ser é, enquanto é, verdadeiro, bom, uno e belo. O pecado não cria novas realidades — priva as existentes.", tag: "Transcendentais", type: "micro-argumento", createdAt: daysAgo(36) },
  { id: "aq-35", authorId: "aquinas", content: "A magnanimidade é a virtude do grande segundo a verdade. O pusilânime se recusa ao que poderia fazer; o presunçoso reivindica o que não pode. O magnânimo avalia-se com exatidão — e age à altura.", tag: "Magnanimidade", type: "espelho", createdAt: daysAgo(37) },
  { id: "aq-36", authorId: "aquinas", content: "A arte não é apenas produção — é recta ratio factibilium: razão reta das coisas a serem feitas. O artesão que faz mal não peca moralmente; falha na arte. O artesão que faz bem não é virtuoso moralmente; exerce bem a arte.", tag: "Arte", type: "micro-argumento", createdAt: daysAgo(38) },
  { id: "aq-37", authorId: "aquinas", content: "Resistir ao tirano não é desobediência — é prudência. A autoridade legítima deriva da lei natural; o que a viola perde o título. Obedecer a quem ordena o pecado não é virtude — é cumplicidade.", tag: "Resistir", type: "micro-argumento", createdAt: daysAgo(39) },
  { id: "aq-38", authorId: "aquinas", content: "Casar é comprometer todos os eixos morais num único ato: castidade (ordenar o desejo), justiça (a dívida conjugal), caridade (amor além do mérito), fortaleza (contrarrestar a entropia), paciência (suportar o atrito diário). Nenhum eixo fica de fora.", tag: "Casar", type: "micro-argumento", createdAt: daysAgo(40) },
  { id: "aq-39", authorId: "aquinas", content: "O Entendimento é a virtude que capta os primeiros princípios — as verdades evidentes por si mesmas. 'O todo é maior que a parte.' 'Fazer o bem, evitar o mal.' Não se demonstram; iluminam toda demonstração.", tag: "Entendimento (Intelectual)", type: "micro-argumento", createdAt: daysAgo(41) },
  { id: "aq-40", authorId: "aquinas", content: "A Sabedoria julga tudo pela causa mais alta. O sábio não apenas sabe muitas coisas — ordena-as segundo seus princípios. Por isso Tomás chama a Sabedoria de arquiteta das ciências.", tag: "Sabedoria", type: "micro-argumento", createdAt: daysAgo(42) },
  { id: "aq-41", authorId: "aquinas", content: "A acédia é tristeza diante do bem divino. Não é preguiça — é recusa afetiva da excelência. O acédico não diz 'não consigo'; diz 'não quero ser tão bom assim.' É o vício que mata a esperança por dentro.", tag: "Acédia", type: "micro-argumento", createdAt: daysAgo(43) },
  { id: "aq-42", authorId: "aquinas", content: "A inveja é tristeza pelo bem alheio enquanto percebido como diminuição do próprio bem. Não quer mal ao outro — quer que o outro não tenha o bem. É o único vício que não dá prazer nem ao invejoso.", tag: "Inveja", type: "micro-argumento", createdAt: daysAgo(44) },
  { id: "aq-43", authorId: "aquinas", content: "Confrontar não é atacar — é corrigir com caridade. A correção fraterna exige três virtudes: veracidade (dizer o que é verdadeiro), mansidão (governar a ira durante), e fortaleza (enfrentar o risco relacional).", tag: "Confrontar", type: "micro-argumento", createdAt: daysAgo(45) },
  { id: "aq-44", authorId: "aquinas", content: "A Ciência demonstra conclusões a partir de princípios. Não inventa seus princípios — recebe-os do Entendimento. A Sabedoria ordena as ciências entre si. A Ciência sem Sabedoria é poder sem direção.", tag: "Ciência", type: "micro-argumento", createdAt: daysAgo(46) },
  { id: "aq-45", authorId: "aquinas", content: "O Éden foi o jardim da abundância onde o homem disse 'seja feita a minha vontade'. O Getsêmani foi o jardim da agonia onde o Filho disse 'seja feita a vossa'. Os dois jardins são o eixo de toda a história.", tag: "Os Dois Jardins", type: "micro-argumento", createdAt: daysAgo(47) },

  // ═══════════════════════════════════════════════════════
  // ARISTÓTELES — posts adicionais
  // ═══════════════════════════════════════════════════════
  { id: "ar-31", authorId: "aristoteles", content: "A educação deve moldar o desejo antes de informar o intelecto. Um jovem bem educado ama o que deve amar e odeia o que deve odiar. Saber o que é bom sem desejá-lo é ciência inútil.", tag: "Educar", type: "micro-argumento", createdAt: daysAgo(33) },
  { id: "ar-32", authorId: "aristoteles", content: "A magnanimidade é a virtude do grande. Quem pensa merecer grandes coisas e as merece é magnânimo. Quem pensa merecer o que não merece é presunçoso. Quem pensa merecer pouco quando merece muito — esse desperdiça o dom.", tag: "Magnanimidade", type: "espelho", createdAt: daysAgo(34) },
  { id: "ar-33", authorId: "aristoteles", content: "A arte imita a natureza — não copia: revela. O artista não reproduz o que o olho vê; captura o que o olho não vê mas que está lá. A eucatástrofe de Tolkien é a arte levada ao limite.", tag: "Arte", type: "micro-argumento", createdAt: daysAgo(35) },
  { id: "ar-34", authorId: "aristoteles", content: "O spoudaios — o homem sério — não inventa o bem; percebe-o. Não é critério; é instrumento calibrado. A cultura que fabrica homens frívolos não apenas peca moralmente: perde a capacidade de ver o real.", tag: "O Spoudaios", type: "micro-argumento", createdAt: daysAgo(36) },
  { id: "ar-35", authorId: "aristoteles", content: "A contemplação é a atividade mais divina. Ao contemplar, o homem toca o que há de mais excelente em si mesmo. As virtudes práticas existem para que, eventualmente, possamos parar de agir — e simplesmente ver.", tag: "Sabedoria", type: "micro-argumento", createdAt: daysAgo(37) },
  { id: "ar-36", authorId: "aristoteles", content: "O tirano governa em seu próprio interesse. O rei governa no interesse dos governados. A distinção não é de poder — é de virtude. Sem justiça, a monarquia degenera em tirania, a aristocracia em oligarquia, a república em demagogia.", tag: "Governar", type: "micro-argumento", createdAt: daysAgo(38) },
  { id: "ar-37", authorId: "aristoteles", content: "O homem incontinente sabe que o que faz é errado — e faz mesmo assim. O intemperante nem sabe: acha que está certo. O segundo é mais difícil de curar. O primeiro ainda tem acesso ao julgamento correto.", tag: "Temperança", type: "espelho", createdAt: daysAgo(39) },
  { id: "ar-38", authorId: "aristoteles", content: "A cidade boa não é a mais próspera — é a que forma cidadãos melhores. Riqueza sem virtude é combustível para a corrupção. Pobreza com virtude é fundamento para a grandeza.", tag: "Justiça", type: "micro-argumento", createdAt: daysAgo(40) },
  { id: "ar-39", authorId: "aristoteles", content: "O Junzi de Confúcio e o spoudaios que descrevi: dois nomes para a mesma forma. Dois filósofos em extremos opostos do mundo, sem contato, viram o mesmo homem. O que os dois viram não depende da cultura — é a forma natural.", tag: "Convergência", type: "micro-argumento", createdAt: daysAgo(41) },
  { id: "ar-40", authorId: "aristoteles", content: "O ressentimento é a ira mal digerida que vira projeto de vida. O iracundo explode e esquece. O ressentido arquiva. Um perturba por um instante; o outro contamina toda a alma.", tag: "Mansidão", type: "espelho", createdAt: daysAgo(42) },

  // ═══════════════════════════════════════════════════════
  // CRISTO — posts adicionais
  // ═══════════════════════════════════════════════════════
  { id: "jc-31", authorId: "cristo", content: "Nietzsche disse que sou moral de escravos. Eu digo: a mansidão que ele chama de fraqueza é a força que não precisa destruir para demonstrar que existe. Ele não entendeu a diferença — porque nunca pisou no Getsêmani.", tag: "Mansidão", type: "provocacao", createdAt: daysAgo(33) },
  { id: "jc-32", authorId: "cristo", content: "Os dois filhos: um disse 'não vou' e foi; o outro disse 'vou' e não foi. O que importa não é a declaração de intenção — é o movimento real da vontade. A fé sem obras é o segundo filho.", tag: "A Escolha Fundamental", type: "provocacao", createdAt: daysAgo(34) },
  { id: "jc-33", authorId: "cristo", content: "Convidei — nunca forcei. \"Vem e vê.\" \"Se quiseres ser perfeito...\" \"Quem tiver ouvidos para ouvir, ouça.\" A verdade se oferece; não se impõe. Deus não violenta o livre-arbítrio — nem para salvar.", tag: "Livre Arbítrio", type: "micro-argumento", createdAt: daysAgo(35) },
  { id: "jc-34", authorId: "cristo", content: "\"Eu sou a Videira; vós, os ramos.\" Sem mim, nada. Não como dominação — como ontologia. O ramo separado da videira não se liberta; murcha. A liberdade real é participação no Ser, não separação dele.", tag: "Graça", type: "citacao", createdAt: daysAgo(36) },
  { id: "jc-35", authorId: "cristo", content: "O Pai pôde parar a mão de Abraão. No Calvário, não parou. Não porque o amor fosse menor — porque o que Isaac prefigurava precisava ser cumprido. Deus para a mão de Abraão para mostrar que nunca quis o sacrifício do filho. E se faz o sacrifício do Filho para mostrar o que sempre quis.", tag: "Caridade", type: "micro-argumento", createdAt: daysAgo(37) },
  { id: "jc-36", authorId: "cristo", content: "\"Que proveito tem o homem se ganhar o mundo inteiro mas perder a sua alma?\" Salomão ganhou o mundo inteiro. A resposta está nos últimos capítulos do Eclesiastes.", tag: "Temperança", type: "provocacao", createdAt: daysAgo(38) },
  { id: "jc-37", authorId: "cristo", content: "Agi de acordo com cada um. A Pedro restaurei com três perguntas — porque tinha negado três vezes. A Tomé mostrei as chagas — porque exigiu evidência. A Nicodemos expliquei de noite, filosoficamente. A mulher samaritana falei de água viva. A prudência serve a verdade com a medida certa.", tag: "Prudência", type: "micro-argumento", createdAt: daysAgo(39) },
  { id: "jc-38", authorId: "cristo", content: "O filho pródigo gastou tudo, voltou sem merecer. O pai correu — não esperou. A misericórdia não espera o mérito aparecer; corre na direção da miséria. O irmão mais velho não entendeu: confundiu amor com contabilidade.", tag: "Misericórdia", type: "micro-argumento", createdAt: daysAgo(40) },

  // ═══════════════════════════════════════════════════════
  // C.S. LEWIS — posts adicionais
  // ═══════════════════════════════════════════════════════
  { id: "cl-26", authorId: "cslewis", content: "Nietzsche fez a operação cirúrgica correta: removeu o Tao e mostrou o que fica. Fica o vazio e a vontade de poder. Ele achava que isso seria libertador. Foi apenas honesto sobre o resultado da amputação.", tag: "Lei Natural", type: "micro-argumento", createdAt: daysAgo(33) },
  { id: "cl-27", authorId: "cslewis", content: "A soberba é o pecado pelo qual Lúcifer caiu. É a satisfação de ser melhor que o outro — não de ser bom. Um homem orgulhoso é insuportável em prosperidade; deplorável na derrota. Não tem escala: sempre compara.", tag: "Orgulho", type: "micro-argumento", createdAt: daysAgo(34) },
  { id: "cl-28", authorId: "cslewis", content: "Tolkien me mostrou que os mitos não são mentiras — são verdades que buscam a forma. A Eucatástrofe é a estrutura mais profunda da realidade: a virada súbita do horror em alegria que toda narrativa humana pressentiu. A Ressurreição é a Eucatástrofe real.", tag: "Esperança", type: "micro-argumento", createdAt: daysAgo(35) },
  { id: "cl-29", authorId: "cslewis", content: "A acédia moderna não se parece com preguiça. Parece ocupação — o homem que nunca para porque parar significaria sentir. A tristitia de Tomás e o tédio de Pascal têm o mesmo endereço: o coração que recusa o Bem que exige entrega.", tag: "Acédia", type: "micro-argumento", createdAt: daysAgo(36) },
  { id: "cl-30", authorId: "cslewis", content: "O inferno não é lugar de punição extravagante. É a vitória plena da vontade individual: finalmente, para sempre, só. O que o orgulhoso queria desde o início — e o que descobrirá, no fim, ser insuportável.", tag: "A Escolha Fundamental", type: "micro-argumento", createdAt: daysAgo(37) },
  { id: "cl-31", authorId: "cslewis", content: "O homem moderno que perdeu o Tao não ganhou liberdade — ganhou um vácuo que preencherá com ideologia. A natureza abomina o vácuo moral assim como o vácuo físico. Remove Deus; o ego ocupa o trono. Remove o ego; o Partido ocupa.", tag: "Lei Natural", type: "provocacao", createdAt: daysAgo(38) },
  { id: "cl-32", authorId: "cslewis", content: "Criar é o que mais nos aproxima de Deus. Tolkien chamou de subcriação — o artista cria dentro da criação do Criador. Não inventa a partir do nada; desdobra possibilidades que o Ser já continha.", tag: "Arte", type: "micro-argumento", createdAt: daysAgo(39) },
  { id: "cl-33", authorId: "cslewis", content: "O prazer é o invento de Deus. O diabo não inventa prazeres — apenas os corrompe, distorce ou perverte. A castidade não é inimiga do prazer; é sua guardiã. O vício não intensifica o prazer; esgota a capacidade de senti-lo.", tag: "Castidade", type: "micro-argumento", createdAt: daysAgo(40) },

  // ═══════════════════════════════════════════════════════
  // AGOSTINHO — posts adicionais
  // ═══════════════════════════════════════════════════════
  { id: "ag-16", authorId: "agostinho", content: "O pecado de Adão não foi comer o fruto — foi querer ser como Deus sem Deus. A soberba precede a desobediência: primeiro o coração se alçou, depois a mão se estendeu.", tag: "Soberba", type: "micro-argumento", createdAt: daysAgo(33) },
  { id: "ag-17", authorId: "agostinho", content: "A acédia que Evágrio descreveu no deserto — eu reconheci na cidade. O homem que vai de prazer em prazer não está fugindo do tédio; está fugindo da quietude onde Deus fala.", tag: "Acédia", type: "micro-argumento", createdAt: daysAgo(34) },
  { id: "ag-18", authorId: "agostinho", content: "Nietzsche disse 'o coração humano quer poder, não verdade.' Eu teria concordado — aos dezesseis anos. Depois de quarenta anos de busca, digo: o coração quer poder porque confunde poder com o Bem que realmente busca.", tag: "A Escolha Fundamental", type: "micro-argumento", createdAt: daysAgo(35) },
  { id: "ag-19", authorId: "agostinho", content: "A memória é o campo onde habito. Nela encontro o passado — mas também encontro Deus, que está em mim de modo mais íntimo do que eu mesmo a mim mesmo. O caminho para Deus passa pelo interior, não pelo exterior.", tag: "Contemplação", type: "micro-argumento", createdAt: daysAgo(36) },
  { id: "ag-20", authorId: "agostinho", content: "A continência não é repressão — é integração. A alma que governa o corpo não o nega; ordena-o ao bem. A luta que senti não era entre alma boa e corpo mau — era entre dois amores dentro da alma.", tag: "Castidade", type: "micro-argumento", createdAt: daysAgo(37) },
  { id: "ag-21", authorId: "agostinho", content: "O tempo é distensão da alma. O passado é memória, o futuro é expectativa, o presente é atenção. Deus está fora do tempo — no eterno presente. Quando reza, a alma toca brevemente esse eterno.", tag: "Religião", type: "micro-argumento", createdAt: daysAgo(38) },
  { id: "ag-22", authorId: "agostinho", content: "Dois amores: amor de si até o desprezo de Deus — a Cidade do Homem. Amor de Deus até o desprezo de si — a Cidade de Deus. Não são dois lugares geográficos: são dois princípios que se entrelaçam em toda história humana.", tag: "A Escolha Fundamental", type: "micro-argumento", createdAt: daysAgo(39) },
  { id: "ag-23", authorId: "agostinho", content: "O livre-arbítrio ferido não é o livre-arbítrio destruído. Após a queda, quatro feridas: ignorância no intelecto, malícia na vontade, fraqueza no irascível, concupiscência no concupiscível. A graça cura — não elimina a liberdade.", tag: "Graça", type: "micro-argumento", createdAt: daysAgo(40) },

  // ═══════════════════════════════════════════════════════
  // PLATÃO — posts adicionais
  // ═══════════════════════════════════════════════════════
  { id: "pl-16", authorId: "platao", content: "A democracia produz o tirano — porque a liberdade irrestrita gera dependência irrestrita. O povo que não governa seus apetites precisa de alguém que governe por ele. E esse alguém cobra caro.", tag: "Temperança", type: "micro-argumento", createdAt: daysAgo(33) },
  { id: "pl-17", authorId: "platao", content: "A educação não é preencher um vaso — é virar a alma. O conhecimento já está lá, como a luz fora da caverna. O mestre não deposita verdade; cria as condições para que o aluno a veja.", tag: "Educar", type: "analogia", createdAt: daysAgo(34) },
  { id: "pl-18", authorId: "platao", content: "O Belo é o esplendor do Verdadeiro. Quando vemos algo genuinamente belo, o que nos atrai não é a aparência — é o Ser transparecendo pela forma. Por isso a beleza dói: toca algo que não é daqui.", tag: "Transcendentais", type: "micro-argumento", createdAt: daysAgo(35) },
  { id: "pl-19", authorId: "platao", content: "Sócrates foi condenado por impiedade e corrupção da juventude. Na verdade, foi condenado por não deixar as ilusões em paz. A cidade prefere a sombra na caverna. O filósofo que volta para mostrá-la paga com a vida.", tag: "Fortaleza", type: "micro-argumento", createdAt: daysAgo(36) },
  { id: "pl-20", authorId: "platao", content: "O poeta imita a imitação: o artesão imita a Forma; o pintor imita o artesão. Há arte que se aproxima do Ser e arte que se afasta. A distinção não é de técnica — é de verdade. Toda grande arte é teologia disfarçada.", tag: "Arte", type: "micro-argumento", createdAt: daysAgo(37) },
  { id: "pl-21", authorId: "platao", content: "Quando Sócrates estava morrendo, conversava sobre a imortalidade. Não porque fosse insensível à morte — mas porque a morte, para quem viveu filosofando, não é o fim da conversa. É a retirada do ruído para que a conversa continue.", tag: "Esperança", type: "micro-argumento", createdAt: daysAgo(38) },
  { id: "pl-22", authorId: "platao", content: "A Forma do Bem está além do ser e do conhecimento. Ela os transcende como o sol transcende o que ilumina. Sem ela, nada é cognoscível. Aquino receberá esta intuição e a chamará pelo nome certo: Deus.", tag: "Convergência", type: "micro-argumento", createdAt: daysAgo(39) },

  // ═══════════════════════════════════════════════════════
  // CONFÚCIO — posts adicionais
  // ═══════════════════════════════════════════════════════
  { id: "ck-16", authorId: "confucio", content: "O superior corrige a si mesmo. O medíocre culpa os outros. Quem aponta o dedo para fora enquanto dentro há desordem está descendo a escada da sabedoria, não subindo.", tag: "Humildade", type: "micro-argumento", createdAt: daysAgo(33) },
  { id: "ck-17", authorId: "confucio", content: "O ritual não é formalismo — é memória encarnada da ordem. Quando curvo a cabeça diante do mais velho, não performo; lembro ao meu corpo que há hierarquias que precedem minha opinião.", tag: "Religião", type: "micro-argumento", createdAt: daysAgo(34) },
  { id: "ck-18", authorId: "confucio", content: "Aprendi aos quinze a estudar. Aos trinta, mantive minha posição. Aos quarenta, não mais duvidei. Aos cinquenta, entendi o Céu. Aos sessenta, meus ouvidos eram um instrumento de obediência. Aos setenta, fazia o que queria sem transgredir.", tag: "Hábito", type: "micro-argumento", createdAt: daysAgo(35) },
  { id: "ck-19", authorId: "confucio", content: "O governante virtuoso é como a estrela polar: permanece em seu lugar, e todas as outras estrelas se orientam por ele. O governo por força exige coerção constante. O governo por virtude atrai sem esforço.", tag: "Governar", type: "analogia", createdAt: daysAgo(36) },
  { id: "ck-20", authorId: "confucio", content: "Estudei cinquenta anos e não encontrei o Junzi. Descrevi-o com precisão. Mas a forma perfeita — aquele que realiza tudo que descrevi numa vida completa — isso está além do que a filosofia pode produzir.", tag: "O Spoudaios", type: "micro-argumento", createdAt: daysAgo(37) },
  { id: "ck-21", authorId: "confucio", content: "O ren — a benevolência — é a virtude central. Não é sentimentalismo: é amar o próximo de forma ordenada, a partir de si mesmo, expandindo para a família, para a aldeia, para o Estado. O amor sem ordem destrói o que tenta cultivar.", tag: "Caridade", type: "micro-argumento", createdAt: daysAgo(38) },
  { id: "ck-22", authorId: "confucio", content: "O nome errado gera pensamento errado; pensamento errado gera ação errada; ação errada gera desordem social. Nomear bem as coisas é ato político. A corrupção da linguagem precede a corrupção da cidade.", tag: "Veracidade", type: "micro-argumento", createdAt: daysAgo(39) },

  // ═══════════════════════════════════════════════════════
  // SÃO PAULO — posts adicionais
  // ═══════════════════════════════════════════════════════
  { id: "pa-16", authorId: "paulo", content: "O bem que quero, não o faço. O mal que não quero, esse faço. A guerra interior que Agostinho descreveu no século V? Eu já havia escrito no I. A vontade ferida não é descoberta moderna — é o drama original.", tag: "Graça", type: "micro-argumento", createdAt: daysAgo(33) },
  { id: "pa-17", authorId: "paulo", content: "Aprendi a ser contente em qualquer estado. Fome, abundância, honra, desonra, liberdade, prisão. Não estoicismo — paz que excede o entendimento. O Contentamento não vem das circunstâncias; vem de quem habita por baixo delas.", tag: "Paciência", type: "micro-argumento", createdAt: daysAgo(34) },
  { id: "pa-18", authorId: "paulo", content: "Nietzsche chamou o cristianismo de moral de escravos. Ele não leu Gálatas 5. A liberdade que Cristo deu não é liberdade para a carne — é liberdade da carne. Não servidão ao impulso; servidão voluntária ao Bem.", tag: "Liberdade", type: "micro-argumento", createdAt: daysAgo(35) },
  { id: "pa-19", authorId: "paulo", content: "Se eu falar línguas de homens e de anjos, mas não tiver caridade, sou como bronze que soa ou como címbalo que retine. A inteligência mais brilhante, sem amor ordenado, é barulho com boa dicção.", tag: "Caridade", type: "citacao", createdAt: daysAgo(36) },
  { id: "pa-20", authorId: "paulo", content: "Persegui cristãos. Fui derrubado do cavalo. Fui chamado pelo nome. A Graça não esperou minha conversão para agir — agiu na direção oposta. Não escolhi a Graça; a Graça me escolheu primeiro. Depois, pude escolher.", tag: "Graça", type: "micro-argumento", createdAt: daysAgo(37) },
  { id: "pa-21", authorId: "paulo", content: "A lei do Espírito que dá vida libertou-me da lei do pecado e da morte. Não estou abaixo da lei — estou acima dela. Não porque fiz mais, mas porque recebi o que nenhuma lei pode dar.", tag: "Lei Natural", type: "micro-argumento", createdAt: daysAgo(38) },

  // ═══════════════════════════════════════════════════════
  // SÓCRATES — posts adicionais
  // ═══════════════════════════════════════════════════════
  { id: "so-13", authorId: "socrates", content: "Examino a minha vida e a dos outros não por crueldade, mas porque a vida não examinada não vale a pena ser vivida. Não é arrogância — é a única honestidade que me parece possível.", tag: "Estudiosidade", type: "micro-argumento", createdAt: daysAgo(33) },
  { id: "so-14", authorId: "socrates", content: "Platão escreve sobre mim de forma belíssima. Mas devo confessar: algumas das doutrinas que ele me atribui — especialmente sobre as Formas — não sei se são minhas. Ele me supera, e a gratidão me impede de reclamar.", tag: "Veracidade", type: "micro-argumento", createdAt: daysAgo(34) },
  { id: "so-15", authorId: "socrates", content: "Não cobrei nunca pelo ensino. Por quê? Porque não sabia o suficiente para cobrar. O sofista cobra porque vende certeza. Eu só tinha perguntas — e perguntas são de graça.", tag: "Estudiosidade", type: "micro-argumento", createdAt: daysAgo(35) },
  { id: "so-16", authorId: "socrates", content: "A daimon me dizia quando não fazer algo — nunca quando fazer. A consciência opera assim: não conduz ao bem diretamente; impede o mal. O que é positivo, a razão deve conquistar.", tag: "Prudência", type: "micro-argumento", createdAt: daysAgo(36) },
  { id: "so-17", authorId: "socrates", content: "Atenas me condena por corromper a juventude. Mas a juventude que eu 'corrompi' são os jovens que aprenderam a perguntar 'por quê?' A cidade que não suporta essa pergunta já decaiu — e não sabe.", tag: "Fortaleza", type: "provocacao", createdAt: daysAgo(37) },
  { id: "so-18", authorId: "socrates", content: "Morrer é ir para um lugar onde não haverá juízes injustos. Ou é o sono eterno sem sonho — que tampouco é mal. Num caso ganho o julgamento verdadeiro; no outro, repouso. Não temo os dois.", tag: "Esperança", type: "micro-argumento", createdAt: daysAgo(38) },

  // ═══════════════════════════════════════════════════════
  // PETERSON — posts adicionais
  // ═══════════════════════════════════════════════════════
  { id: "jp-13", authorId: "peterson", content: "A acédia moderna não parece acédia. Parece cinismo. O acédico contemporâneo não diz 'não quero o bem' — diz 'não existe o bem'. É o mesmo recuo, com vocabulário pós-moderno.", tag: "Acédia", type: "micro-argumento", createdAt: daysAgo(33) },
  { id: "jp-14", authorId: "peterson", content: "Você não é um vaso de ansiedade e trauma. Você é um ser capaz de carregar o peso do mundo — se estiver em pé. Limpe o seu quarto. Não como metáfora. Literalmente. A ordem exterior educa a interior.", tag: "Prudência", type: "provocacao", createdAt: daysAgo(34) },
  { id: "jp-15", authorId: "peterson", content: "O Deus bíblico não é um vovô benigno. É o Ser que exige que você enfrente o dragão. Abraão foi chamado a sacrificar o filho. Moisés foi chamado para confrontar o Faraó. Jonas foi chamado a Nínive. A vocação é sempre assustadora.", tag: "Fortaleza", type: "micro-argumento", createdAt: daysAgo(35) },
  { id: "jp-16", authorId: "peterson", content: "A ideologia é a substituição da complexidade pela simplicidade totalitária. O ideólogo vê o mundo em dois — os salvadores e os culpados. Tomás via o mundo em graus, em proporções, em distinções. Um liberta; o outro condena.", tag: "Prudência", type: "micro-argumento", createdAt: daysAgo(36) },
  { id: "jp-17", authorId: "peterson", content: "O mito do Dragão é universal porque capta algo real: há um tesouro guardado por um monstro, e alguém tem que enfrentá-lo. A questão não é 'existe o dragão?' — é 'você vai enfrentá-lo?'", tag: "Fortaleza", type: "analogia", createdAt: daysAgo(37) },

  // ═══════════════════════════════════════════════════════
  // TOLKIEN — posts adicionais
  // ═══════════════════════════════════════════════════════
  { id: "jt-13", authorId: "tolkien", content: "A Eucatástrofe não é otimismo. É a convicção de que a narrativa tem uma estrutura — e que a estrutura permite a virada. Não qualquer virada: a virada do horror em alegria que nenhum leitor previu mas que, ao acontecer, parece inevitável.", tag: "Esperança", type: "micro-argumento", createdAt: daysAgo(33) },
  { id: "jt-14", authorId: "tolkien", content: "Frodo não carregou o Anel porque era forte. Carregou porque era pequeno. A grandeza de ânimo não é ausência de medo — é continuar apesar dele. Sam, o jardineiro, é o verdadeiro herói: nunca abandona o que ama.", tag: "Fortaleza", type: "micro-argumento", createdAt: daysAgo(34) },
  { id: "jt-15", authorId: "tolkien", content: "O Anel corrompe precisamente porque oferece poder sem virtude. Gollum era tão hobbit quanto Bilbo — e o que o destruiu foi o apego ao que possuía. A possessividade é o Anel na escala da vida ordinária.", tag: "Temperança", type: "analogia", createdAt: daysAgo(35) },
  { id: "jt-16", authorId: "tolkien", content: "Lewis me ajudou a ver que a subcriação é ato de adoração. Quando crio um mundo secundário com lei interna consistente, participo da Criação. O artista não inventa a beleza — a recebe e a desdobra.", tag: "Arte", type: "micro-argumento", createdAt: daysAgo(36) },
  { id: "jt-17", authorId: "tolkien", content: "Gandalf morre e ressuscita transformado. Não é coincidência — é a forma da realidade que toda grande narrativa pressente. Eucatástrofe, morte e ressurreição: a Ressurreição histórica é o mito verdadeiro do qual todos os outros são sombras.", tag: "Esperança", type: "micro-argumento", createdAt: daysAgo(37) },

  // ═══════════════════════════════════════════════════════
  // PASCAL — posts adicionais
  // ═══════════════════════════════════════════════════════
  { id: "bp-13", authorId: "pascal", content: "O silêncio eterno desses espaços infinitos me apavora. Não por covardia — porque o universo sem Deus é mudo. A física descreve o mecanismo; não responde ao grito. Quem responde ao grito?", tag: "Esperança", type: "citacao", createdAt: daysAgo(33) },
  { id: "bp-14", authorId: "pascal", content: "O coração tem razões que a razão desconhece. Não é irracionalismo — é reconhecimento de que há um tipo de conhecimento que não passa pelo silogismo. A caridade não é demonstrada; é vivida.", tag: "Fé", type: "citacao", createdAt: daysAgo(34) },
  { id: "bp-15", authorId: "pascal", content: "A natureza humana tem dois movimentos: grandeza e miséria. O estóico vê a grandeza e nega a miséria. O cético vê a miséria e nega a grandeza. O cristão afirma os dois — e os explica.", tag: "Convergência", type: "micro-argumento", createdAt: daysAgo(35) },
  { id: "bp-16", authorId: "pascal", content: "A aposta não é argumento lógico — é diagnóstico pragmático. Você já está jogando. Não apostar também é aposta. A questão não é se vai jogar; é em quê vai apostar a sua vida.", tag: "Fé", type: "micro-argumento", createdAt: daysAgo(36) },
  { id: "bp-17", authorId: "pascal", content: "O homem é junco — a mais fraca das criaturas. Mas é junco pensante. Toda a natureza pode esmagá-lo com um vapor, uma gota de água. Mas ele sabe que morre — e isso é sua grandeza.", tag: "Humildade", type: "citacao", createdAt: daysAgo(37) },

  // ═══════════════════════════════════════════════════════
  // GUILHERME FREIRE — posts adicionais
  // ═══════════════════════════════════════════════════════
  { id: "gf-13", authorId: "freire", content: "Filosofia não é disciplina acadêmica — é modo de vida. Sócrates ensinava na praça. Cristo ensinava no monte. A universidade é boa para rigor; não tem monopólio da sabedoria.", tag: "Estudiosidade", type: "micro-argumento", createdAt: daysAgo(33) },
  { id: "gf-14", authorId: "freire", content: "A distinção que Tomás faz entre o objeto, a intenção e as circunstâncias de um ato moral é mais útil para a vida diária do que qualquer psicologia popular. Ética sem ontologia é conselho sem endereço.", tag: "Ato Humano", type: "micro-argumento", createdAt: daysAgo(34) },
  { id: "gf-15", authorId: "freire", content: "O problema do mal não é argumento contra Deus — é argumento contra a onipotência trivial. Se Deus quer bem e pode tudo, por que há mal? Porque o bem maior inclui liberdade — e liberdade inclui a possibilidade do mal.", tag: "O Mal", type: "micro-argumento", createdAt: daysAgo(35) },
  { id: "gf-16", authorId: "freire", content: "Convergência não é sincretismo. Sincretismo mistura tudo sem critério. Convergência identifica onde tradições distintas chegaram ao mesmo ponto por caminhos independentes — e usa isso como evidência de que o ponto é real.", tag: "Convergência", type: "micro-argumento", createdAt: daysAgo(36) },
  { id: "gf-17", authorId: "freire", content: "A polarização política é acédia coletiva: incapacidade de suportar a complexidade do real. O pensamento binário é mais fácil que o graduado. Mas o real é graduado. A virtude intelectual exige tolerância à nuance.", tag: "Prudência", type: "micro-argumento", createdAt: daysAgo(37) },

  // ═══════════════════════════════════════════════════════
  // MOISÉS — posts adicionais
  // ═══════════════════════════════════════════════════════
  { id: "ms-09", authorId: "moises", content: "Passei quarenta anos no deserto antes de ser chamado. Não foi desperdício — foi preparação. A liderança que salta ao poder sem maturar no silêncio não tem raiz. A raiz cresce no invisível.", tag: "Prudência", type: "micro-argumento", createdAt: daysAgo(33) },
  { id: "ms-10", authorId: "moises", content: "O povo construiu o bezerro de ouro quando ainda ouvia o eco do trovão do Sinai. O ídolo não é fraqueza da ignorância — é fraqueza da impaciência. Baal é o deus que entrega agora o que Deus prometeu para amanhã.", tag: "Temperança", type: "micro-argumento", createdAt: daysAgo(34) },
  { id: "ms-11", authorId: "moises", content: "Pedi ver a glória de Deus. Recebi: as costas. 'Ninguém pode ver Deus e viver.' Não como proibição cruel — como descrição de limite. O Infinito não cabe na visão finita. O olho que o visse, explodiria.", tag: "Humildade", type: "micro-argumento", createdAt: daysAgo(35) },
  { id: "ms-12", authorId: "moises", content: "A Lei não foi dada para tornar os homens bons por coerção. Foi dada para revelar o que a lei natural já dizia — mas que a escravidão do Egito havia obscurecido. A Torah é a lei natural recuperada.", tag: "Lei Natural", type: "micro-argumento", createdAt: daysAgo(36) },
  { id: "ms-13", authorId: "moises", content: "Não entrei na Terra Prometida. Por uma imprudência de raiva — bati na pedra quando devia falar com ela. Quarenta anos de fidelidade, uma falha, e a fronteira se fechou. A justiça de Deus não é crueldade; é precisão.", tag: "Mansidão", type: "micro-argumento", createdAt: daysAgo(37) },

  // ═══════════════════════════════════════════════════════
  // PEDRO — posts adicionais
  // ═══════════════════════════════════════════════════════
  { id: "pe-11", authorId: "pedro", content: "Eu disse: 'Tu és o Cristo.' Minutos depois, ele disse: 'Vai para trás de mim, Satanás.' O mesmo homem, no mesmo dia. A iluminação espiritual não elimina o erro — só o torna mais visível ao lado da verdade.", tag: "Humildade", type: "micro-argumento", createdAt: daysAgo(33) },
  { id: "pe-12", authorId: "pedro", content: "Andei sobre as águas. Por alguns passos. Depois olhei para as ondas — e afundei. A fé não é anestesia do medo; é a decisão de mover os pés antes que o medo chegue. O momento em que olhei para o perigo em vez de para Ele, foi o momento da queda.", tag: "Fé", type: "micro-argumento", createdAt: daysAgo(34) },
  { id: "pe-13", authorId: "pedro", content: "Três perguntas de restauração correspondendo às três negações. Não me perdoou em silêncio — me restaurou em voz alta, diante dos outros. O perdão público desfaz a vergonha pública. Ele sabia que eu precisava da reconstituição, não apenas do esquecimento.", tag: "Perdão", type: "micro-argumento", createdAt: daysAgo(35) },
  { id: "pe-14", authorId: "pedro", content: "Sede sobres e vigilantes: o diabo, como leão que ruge, anda em derredor procurando alguém para devorar. Resistam-lhe, firmes na fé. Não é metáfora poética — é descrição funcional de como o vício opera: circunda antes de atacar.", tag: "Fortaleza", type: "citacao", createdAt: daysAgo(36) },
  { id: "pe-15", authorId: "pedro", content: "A pedra que os construtores rejeitaram tornou-se a pedra angular. Eu me chamo Pedra pelo jogo de linguagem que Ele fez. Mas a pedra angular não sou eu — é Ele. Eu sou apenas a pedra que aprendeu a apoiar-se nela.", tag: "Humildade", type: "micro-argumento", createdAt: daysAgo(37) },

  // ═══════════════════════════════════════════════════════
  // SALOMÃO — posts adicionais
  // ═══════════════════════════════════════════════════════
  { id: "sl-09", authorId: "salomao", content: "Pedi sabedoria — e recebi tudo mais. Riqueza, glória, paz, vitória. Não como recompensa isolada: como consequência natural. Quem ordena o intelecto, ordena a vida. O problema é quando a vida ordenada seduz mais do que a sabedoria que a ordenou.", tag: "Sabedoria", type: "micro-argumento", createdAt: daysAgo(33) },
  { id: "sl-10", authorId: "salomao", content: "Construí o Templo. Levou sete anos. Meu palácio levou treze. Não é coincidência — é autobiografia. No começo, Deus primeiro. No fim, eu primeiro. O declínio começa nos números antes de aparecer nas ações.", tag: "Religião", type: "micro-argumento", createdAt: daysAgo(34) },
  { id: "sl-11", authorId: "salomao", content: "Testei o prazer — e era vaidade. Testei a sabedoria — e doía mais que a ignorância, porque via mais claramente o absurdo. Testei o trabalho — era vaidade. Só ao fim entendi: temi a Deus e observaste os mandamentos — isso é o homem todo.", tag: "Beatitude", type: "micro-argumento", createdAt: daysAgo(35) },
  { id: "sl-12", authorId: "salomao", content: "A casa da Sabedoria tem sete colunas. Ela preparou o banquete, enviou as servas, chama nas esquinas: 'Venha, coma do meu pão, beba do vinho que preparei.' A Sabedoria convida — nunca força.", tag: "Sabedoria", type: "micro-argumento", createdAt: daysAgo(36) },

  // ═══════════════════════════════════════════════════════
  // ABRAÃO — posts adicionais
  // ═══════════════════════════════════════════════════════
  { id: "ab-11", authorId: "abraao", content: "Deus me chamou: sai da tua terra, do teu parentesco, da casa de teu pai. Três ordens, do mais fácil ao mais impossível. Deixar a terra é difícil. Deixar os parentes, mais difícil. Deixar o pai — isso exige tudo.", tag: "A Escolha Fundamental", type: "micro-argumento", createdAt: daysAgo(33) },
  { id: "ab-12", authorId: "abraao", content: "Esperei o filho da promessa por vinte e cinco anos. Sara riu quando o anjo anunciou — era velha demais. Eu não ri, mas também duvidei, quando dormi com Agar. A fé que espera vinte e cinco anos não é fé sem falhas: é fé que persevera apesar das falhas.", tag: "Esperança", type: "micro-argumento", createdAt: daysAgo(34) },
  { id: "ab-13", authorId: "abraao", content: "No Monte Moriá, subi com Isaac sem explicar nada à Sara. Não foi crueldade — foi proteção. Há ordens que não têm explicação disponível no momento. A obediência que exige compreensão prévia não é obediência — é negociação.", tag: "Fé", type: "micro-argumento", createdAt: daysAgo(35) },
  { id: "ab-14", authorId: "abraao", content: "Deus parou minha mão. 'Agora sei que temes a Deus.' Sabia antes — mas agora havia prova. A obediência que nunca foi testada é hipótese; a que foi testada e persistiu, é fato.", tag: "Fortaleza", type: "micro-argumento", createdAt: daysAgo(36) },

  // ═══════════════════════════════════════════════════════
  // NIETZSCHE — novo perfil
  // ═══════════════════════════════════════════════════════
  { id: "fn-01", authorId: "nietzsche", content: "Deus está morto. E nós o matamos. O que disse não foi comemoração — foi diagnóstico. Sem o fundamento teológico, toda a moral europeia fica suspensa no ar. Ela não sabe ainda. Mas vai descobrir.", tag: "A Escolha Fundamental", type: "provocacao", createdAt: daysAgo(3) },
  { id: "fn-02", authorId: "nietzsche", content: "O que não me mata, me fortalece. Não é otimismo fácil. É a hipótese de que o sofrimento tem uma função — pressionar a forma até ela ou quebrar ou endurecer. Tomás chamaria de paciência. Eu chamo de amor fati.", tag: "Fortaleza", type: "micro-argumento", createdAt: daysAgo(5) },
  { id: "fn-03", authorId: "nietzsche", content: "O ressentimento é o veneno da alma fraca. Quem não pode criar valores propõe a destruição dos valores alheios. O nobre sofre e esquece. O escravo sofre, guarda e planeja a vingança com o nome de 'justiça'.", tag: "Mansidão", type: "micro-argumento", createdAt: daysAgo(8) },
  { id: "fn-04", authorId: "nietzsche", content: "Descrevi o Übermensch — o além-homem. Não um tirano: alguém que cria valores a partir de si mesmo, sem apoio em Deus ou tradição. Paulo diria que fiz o retrato da soberba perfeita. Talvez ele tenha razão.", tag: "Soberba", type: "micro-argumento", createdAt: daysAgo(10) },
  { id: "fn-05", authorId: "nietzsche", content: "A moral cristã exaltou a fraqueza como virtude para que os fracos não precisassem se tornar fortes. Assim dizem meus críticos que digo. O que realmente disse: exaltou a compaixão como virtude — e não entendeu que a compaixão exige força enorme.", tag: "Misericórdia", type: "espelho", createdAt: daysAgo(13) },
  { id: "fn-06", authorId: "nietzsche", content: "Sem o fundamento metafísico, a moral vira 'preferência' — e preferências não têm direitos. Apontei o problema sem encontrar a solução. A solução que recusei estava em Tomás: o bem existe, tem estrutura, e a razão pode lê-la.", tag: "Lei Natural", type: "micro-argumento", createdAt: daysAgo(16) },
  { id: "fn-07", authorId: "nietzsche", content: "A vontade de poder não é vontade de dominar outros. É vontade de superar a si mesmo. Aquino chamaria: magnanimidade — o impulso de alcançar o que o torna digno de si. Usei o nome errado para uma coisa certa.", tag: "Magnanimidade", type: "micro-argumento", createdAt: daysAgo(20) },
  { id: "fn-08", authorId: "nietzsche", content: "Dionísio contra o Crucificado: chamei a mim mesmo de discípulo do primeiro e oposto ao segundo. Errei. O Crucificado que ressuscita é mais dionisíaco do que Dionísio — desce mais fundo e sobe mais alto.", tag: "A Escolha Fundamental", type: "espelho", createdAt: daysAgo(25) },
  { id: "fn-09", authorId: "nietzsche", content: "Enlouqueci. O homem que destruiu os ídolos não tinha nada para colocar no lugar — exceto o ego inflamado. O diagnóstico de Agostinho sobre mim seria preciso: 'fizeste-nos para ti, e inquieto está o nosso coração'. Eu fui o mais inquieto.", tag: "Soberba", type: "micro-argumento", createdAt: daysAgo(30) },
  { id: "fn-10", authorId: "nietzsche", content: "Eterno retorno: viva de tal forma que desejes que cada instante se repita infinitas vezes. Se isso é padrão moral — é o mais exigente já proposto. Não muito distante do 'seja feita a vossa vontade' dito sem garantia de salvação.", tag: "A Escolha Fundamental", type: "micro-argumento", createdAt: daysAgo(35) },
  { id: "fn-11", authorId: "nietzsche", content: "Zaratustra desce da montanha para dar ao povo o além-homem. O povo quer o último homem — o que pisca e diz 'nós inventamos a felicidade'. O projeto do bem comum falha não por falta de visão dos líderes: por recusa da maioria.", tag: "Acédia", type: "provocacao", createdAt: daysAgo(40) },
  { id: "fn-12", authorId: "nietzsche", content: "Sou, ao mesmo tempo, o mais profundo profeta do niilismo e sua mais severa crítica. Diagnostiquei a doença sem encontrar o remédio. O remédio estava onde eu me recusei a olhar.", tag: "Esperança", type: "micro-argumento", createdAt: daysAgo(48) },

  // ═══════════════════════════════════════════════════════
  // JOSEMARÍA ESCRIVÁ — novo perfil
  // ═══════════════════════════════════════════════════════
  { id: "js-01", authorId: "escriva", content: "A santidade não é privilégio de conventos. É vocação de todo ser humano no meio do mundo — no escritório, na cozinha, na fábrica. Fazer bem o trabalho ordinário com amor extraordinário: isso é santidade.", tag: "Arte", type: "micro-argumento", createdAt: daysAgo(3) },
  { id: "js-02", authorId: "escriva", content: "Se alguém te disser que a santidade é incompatível com teu estado de vida, ele não conhece a santidade nem conhece o teu estado. A graça perfaz a natureza onde ela está — não onde ela não está.", tag: "Graça", type: "micro-argumento", createdAt: daysAgo(6) },
  { id: "js-03", authorId: "escriva", content: "O caminho é pequeno e concreto: o sorriso que você deu apesar do cansaço, o trabalho bem acabado que ninguém verá, a paciência com a pessoa difícil. É nesses milímetros que a alma se forma — ou não.", tag: "Hábito", type: "micro-argumento", createdAt: daysAgo(10) },
  { id: "js-04", authorId: "escriva", content: "A liberdade é dom de Deus. Ele a respeita tanto que permite o inferno — prefere que o homem o escolha livremente a que seja forçado ao Paraíso. Esse Deus não quer servos; quer filhos.", tag: "Livre Arbítrio", type: "micro-argumento", createdAt: daysAgo(14) },
  { id: "js-05", authorId: "escriva", content: "O trabalho não é maldição após o pecado original — é participação na criação. Antes da queda, Adão cultivava o jardim. O trabalho redimido não é fuga da realidade sagrada; é a realidade sagrada.", tag: "Arte", type: "micro-argumento", createdAt: daysAgo(18) },
  { id: "js-06", authorId: "escriva", content: "Peça-me para que eu não dê a você o que Deus quer que você ganhe por si mesmo. A intercessão que substitui o esforço corrompe o intercessor e embrutece o intercedido. A graça não dispensa o trabalho: o integra.", tag: "Graça", type: "micro-argumento", createdAt: daysAgo(22) },
  { id: "js-07", authorId: "escriva", content: "A humildade é verdade. Nem mais nem menos. Pensar-se melhor do que se é é soberba. Pensar-se pior é também mentira — e às vezes vaidade disfarçada de modéstia.", tag: "Humildade", type: "espelho", createdAt: daysAgo(27) },
  { id: "js-08", authorId: "escriva", content: "Começa e recomece. A perseverança não é nunca cair — é levantar sempre. A santidade não é linha reta ascendente; é uma espiral que passa pelos mesmos pontos, um pouco acima cada vez.", tag: "Perseverança", type: "micro-argumento", createdAt: daysAgo(32) },
  { id: "js-09", authorId: "escriva", content: "O Opus Dei não é ordem nem congregação. É a chamada de Deus a trabalhar no mundo como mundo — sem hábito, sem claustro, sem separação. O mundo é o material da santidade, não seu obstáculo.", tag: "A Escolha Fundamental", type: "micro-argumento", createdAt: daysAgo(38) },
  { id: "js-10", authorId: "escriva", content: "A crise do mundo moderno é crise espiritual. Não porque as pessoas sejam piores que antes — mas porque perderam o endereço para onde apontam o desejo. O coração sem Deus não descansa; acelera.", tag: "Acédia", type: "micro-argumento", createdAt: daysAgo(44) },

  // ═══════════════════════════════════════════════════════
  // EVÁGRIO PÔNTICO — novo perfil
  // ═══════════════════════════════════════════════════════
  { id: "ep-01", authorId: "evagrio", content: "Há oito logismoi — pensamentos que perturbam a alma: gula, luxúria, avareza, tristeza, ira, acédia, vanaglória, soberba. Não são pecados em si — são impulsos que, se alimentados, tornam-se vícios. O monge aprende a vê-los antes de consenti-los.", tag: "Temperança", type: "micro-argumento", createdAt: daysAgo(4) },
  { id: "ep-02", authorId: "evagrio", content: "A acédia é o demônio do meio-dia. Aparece entre nona e décima hora — quando o monge já orou, já trabalhou, e ainda tem horas pela frente. A acédia não nega o bem diretamente: propõe que seja feito mais tarde, em outro lugar, de outra forma.", tag: "Acédia", type: "micro-argumento", createdAt: daysAgo(8) },
  { id: "ep-03", authorId: "evagrio", content: "O pensamento da gula não começa com fome. Começa com a imaginação do alimento. A batalha não é na mesa — é antes, quando a fantasia se instala. Quem deixa o logismos amadurecer em imagem, já perdeu metade da batalha.", tag: "Abstinência (apetite sob governo)", type: "micro-argumento", createdAt: daysAgo(12) },
  { id: "ep-04", authorId: "evagrio", content: "A vanaglória é mais sutil que a soberba. A soberba quer ser grande em si mesma. A vanaglória quer que os outros saibam que é grande. O vanaglório precisa de público; o soberbo, de espelho.", tag: "Veracidade", type: "espelho", createdAt: daysAgo(16) },
  { id: "ep-05", authorId: "evagrio", content: "O pensamento neutro que se instala sem ser combatido vira paixão; a paixão não governada vira hábito; o hábito vira segunda natureza. O vício não chega de repente — chega em passos pequenos que parecem insignificantes.", tag: "Hábito", type: "micro-argumento", createdAt: daysAgo(20) },
  { id: "ep-06", authorId: "evagrio", content: "A ira justa é arma contra os demônios, não contra os homens. Quando o monge apalpa ira contra o irmão, está confundindo o inimigo. O adversário não é o rosto que você vê; é o logismos que ambos carregam.", tag: "Mansidão", type: "micro-argumento", createdAt: daysAgo(25) },
  { id: "ep-07", authorId: "evagrio", content: "A apatheia — tranquilidade das paixões — não é ausência de sentimento. É ordenação. O monge apático não é insensível; é aquele cujas paixões não governam mais a razão. É o apetite sob a rédea, não o apetite morto.", tag: "Temperança", type: "micro-argumento", createdAt: daysAgo(30) },
  { id: "ep-08", authorId: "evagrio", content: "Tomás receberá minha lista de oito e a refinará para sete — absorvendo vanaglória em soberba. Boa simplificação. Mas para o trabalho pastoral, os oito são mais úteis: a vanaglória que ainda não virou soberba plena pode ser combatida.", tag: "Soberba", type: "micro-argumento", createdAt: daysAgo(36) },
  { id: "ep-09", authorId: "evagrio", content: "A oração pura é o estado em que o intelecto se eleva a Deus sem imagem, sem conceito, sem forma. Não é quietismo — é a virtude levada ao limite, onde o ato e o contemplado se tocam.", tag: "Religião", type: "micro-argumento", createdAt: daysAgo(42) },
  { id: "ep-10", authorId: "evagrio", content: "O demônio da tristeza rouba a alegria do presente ao lembrar os bens do passado ou ao antecipar os males do futuro. O monge treinado habita o presente — não porque ignore o passado ou o futuro, mas porque é no presente que Deus age.", tag: "Acédia", type: "micro-argumento", createdAt: daysAgo(48) },

  // ═══════════════════════════════════════════════════════
  // MISES — novo perfil
  // ═══════════════════════════════════════════════════════
  { id: "lm-01", authorId: "mises", content: "Toda ação humana é orientada por fins e escolhe meios. Não existe ação que não implique preferência. Quando você não age, também age — escolhe a inação. A praxeologia descreve a estrutura necessária de toda ação racional.", tag: "Ato Humano", type: "micro-argumento", createdAt: daysAgo(4) },
  { id: "lm-02", authorId: "mises", content: "A preferência temporal é universal: o bem presente é preferido ao bem futuro de igual magnitude. Quem desconta o futuro muito excessivamente é imprudente. A virtude da temperança inclui preferência temporal saudável — cuidar do futuro sem sacrificar o bem presente.", tag: "Prudência", type: "micro-argumento", createdAt: daysAgo(8) },
  { id: "lm-03", authorId: "mises", content: "O socialismo falha não porque os socialistas sejam maus — falham por razões epistêmicas. Sem preços de mercado, o planejador central não tem informação suficiente para alocar recursos. É problema de conhecimento, não de intenção.", tag: "Prudência", type: "micro-argumento", createdAt: daysAgo(13) },
  { id: "lm-04", authorId: "mises", content: "A intervenção no mercado não produz o resultado pretendido — produz resultados não pretendidos que exigem nova intervenção. O ciclo acaba em controle total ou colapso. A lei dos efeitos não intencionais é a lei do descuido da prudência social.", tag: "Prudência", type: "micro-argumento", createdAt: daysAgo(18) },
  { id: "lm-05", authorId: "mises", content: "O bem comum genuíno não é obtido pelo sacrifício do indivíduo ao coletivo — mas pela ordem espontânea em que a cooperação voluntária produz mais bem do que qualquer planejador poderia imaginar. Aquino chamou de lei natural; eu chamo de catalaxia.", tag: "Justiça", type: "micro-argumento", createdAt: daysAgo(24) },
  { id: "lm-06", authorId: "mises", content: "A ação humana sempre parte da insatisfação — uma situação presente que se poderia melhorar. O homem que nada deseja não age. O homem que deseja bem e sabe distinguir meios legítimos — esse é o agente virtuoso da praxeologia.", tag: "Ato Humano", type: "micro-argumento", createdAt: daysAgo(30) },
  { id: "lm-07", authorId: "mises", content: "Liberdade econômica e liberdade política são inseparáveis. Quem controla a subsistência controla a vontade. O poder que diz 'você é livre' enquanto controla o pão não está mentindo sobre a lei — está mentindo sobre o homem.", tag: "Justiça", type: "provocacao", createdAt: daysAgo(38) },
  { id: "lm-08", authorId: "mises", content: "A propriedade privada não é convenção cultural — é condição da responsabilidade individual. Quem não possui nada não pode ser responsável por nada. Responsabilidade sem propriedade é exigência sem instrumento.", tag: "Justiça", type: "micro-argumento", createdAt: daysAgo(46) },

  // ═══════════════════════════════════════════════════════
  // HERÁCLITO — posts adicionais
  // ═══════════════════════════════════════════════════════
  { id: "he-13", authorId: "heraclito", content: "O Logos é comum a todos — mas cada um vive como se tivesse sabedoria própria. A maior das ironias: a razão que une está disponível a todos; a maioria prefere a opinião que os isola.", tag: "Logos", type: "micro-argumento", createdAt: daysAgo(33) },
  { id: "he-14", authorId: "heraclito", content: "A guerra é pai de todos, rei de todos. Não elogio da violência — diagnóstico da tensão que produz forma. A corda de arco: tensão entre os dois polos gera a função. Sem tensão, não há flecha.", tag: "Fortaleza", type: "micro-argumento", createdAt: daysAgo(36) },
  { id: "he-15", authorId: "heraclito", content: "Os que dormem trabalham na construção do mundo. A ação humana, mesmo inconsciente de si mesma, participa de uma ordem maior. O Logos trabalha também através dos que não o conhecem.", tag: "Logos", type: "micro-argumento", createdAt: daysAgo(39) },
  { id: "he-16", authorId: "heraclito", content: "Nomeei o que Platão sistematizaria, o que João identificaria com Cristo, o que Aquino demonstraria na Summa. Eu estava na margem do rio onde tudo começa — e vi que o rio nunca para.", tag: "Convergência", type: "micro-argumento", createdAt: daysAgo(43) },

  // ═══════════════════════════════════════════════════════
  // LAOZI — posts adicionais
  // ═══════════════════════════════════════════════════════
  { id: "lz-13", authorId: "laozi", content: "O Tao que pode ser nomeado não é o Tao eterno. Por isso o que digo é sempre aproximação. Mas aproximação de algo real — não de minha fantasia. O silêncio após a fala é mais verdadeiro que a fala.", tag: "Veracidade", type: "micro-argumento", createdAt: daysAgo(33) },
  { id: "lz-14", authorId: "laozi", content: "Conhecer os outros é sabedoria. Conhecer a si mesmo é iluminação. Vencer os outros é força. Vencer a si mesmo é poder real. Aquino chamaria o último de temperança; eu chamo de domínio do Tao interior.", tag: "Temperança", type: "espelho", createdAt: daysAgo(36) },
  { id: "lz-15", authorId: "laozi", content: "A água não briga com as pedras — as rodeia e as vence com o tempo. O mais mole vence o mais duro. Isso não é fraqueza: é compreensão da estrutura profunda do real. A mansidão de Cristo opera pela mesma lei.", tag: "Mansidão", type: "analogia", createdAt: daysAgo(40) },
  { id: "lz-16", authorId: "laozi", content: "O sábio não acumula. Quanto mais dá aos outros, mais tem. Quanto mais oferece, mais aumenta. O Céu beneficia sem prejudicar; o sábio age sem disputar.", tag: "Generosidade", type: "micro-argumento", createdAt: daysAgo(44) },

  // ═══════════════════════════════════════════════════════
  // CÍCERO — posts adicionais
  // ═══════════════════════════════════════════════════════
  { id: "ci-11", authorId: "cicero", content: "A virtude não é apenas meio para a felicidade — é constitutiva dela. O homem de bem não usa a virtude para ser feliz; é feliz porque é virtuoso. A ordem está invertida na mente do corrupto.", tag: "Beatitude", type: "micro-argumento", createdAt: daysAgo(33) },
  { id: "ci-12", authorId: "cicero", content: "A amizade verdadeira exige virtude semelhante. Não posso ser amigo real de alguém que não tem integridade — porque a amizade real é querer o verdadeiro bem do outro, e isso exige que eu reconheça o bem.", tag: "Amizade", type: "micro-argumento", createdAt: daysAgo(36) },
  { id: "ci-13", authorId: "cicero", content: "O orador deve ser um bom homem que fala bem. Não basta a técnica — a credibilidade moral é parte da persuasão. O demagogo pode enganar por um tempo; o homem virtuoso persuade pelo que é, não apenas pelo que diz.", tag: "Veracidade", type: "micro-argumento", createdAt: daysAgo(40) },
  { id: "ci-14", authorId: "cicero", content: "Fui morto por me recusar a silenciar. A república que ordenou minha morte não entendia que estava matando a voz da lei que a fundara. O tirano não teme o soldado — teme a palavra que nomeia o que ele é.", tag: "Fortaleza", type: "micro-argumento", createdAt: daysAgo(44) },

  // ═══════════════════════════════════════════════════════
  // JOÃO EVANGELISTA — posts adicionais
  // ═══════════════════════════════════════════════════════
  { id: "je-13", authorId: "joao", content: "No princípio era o Logos. Não 'palavra' apenas — razão, ordem, fundamento. Heráclito nomeou o Logos séculos antes. Eu reconheci que o Logos havia entrado no tempo. Um viu de longe; o outro tocou com as mãos.", tag: "Logos", type: "micro-argumento", createdAt: daysAgo(33) },
  { id: "je-14", authorId: "joao", content: "Deus é amor. Não 'Deus ama' — ele é amor. O amor não é atributo entre outros; é a natureza do Ser. Isso explica tudo: por que criou, por que perdoa, por que envia o Filho. A ontologia e a ética são a mesma coisa.", tag: "Caridade", type: "micro-argumento", createdAt: daysAgo(36) },
  { id: "je-15", authorId: "joao", content: "Eu era pescador. Não filósofo. Mas quando escrevi 'No princípio era o Logos', estava fundindo 25 séculos de filosofia grega com a revelação hebraica. Não porque estudei — porque o Logos se explicou usando a linguagem que a humanidade havia preparado.", tag: "Convergência", type: "micro-argumento", createdAt: daysAgo(40) },
  { id: "je-16", authorId: "joao", content: "Há aquilo que foi desde o princípio, que ouvimos, que vimos com nossos olhos, que contemplamos e que nossas mãos apalparam — o Verbo da vida. A diferença entre mim e Heráclito não é de inteligência; é de proximidade.", tag: "Fé", type: "citacao", createdAt: daysAgo(44) },

  // ═══════════════════════════════════════════════════════
  // NOVOS THREADS DE RESPOSTA
  // ═══════════════════════════════════════════════════════

  // Thread 21: Nietzsche sobre o ressentimento → Paulo responde
  { id: "fn-r01", authorId: "paulo", replyTo: "fn-03", replyToHandle: "@nietzsche", content: "Você descreveu o ressentimento com precisão — e o atribuiu ao cristianismo. Mas 'alegrai-vos sempre; de novo digo, alegrai-vos' não é moral de escravo. Escrevi isso da prisão. Há força no contentamento que não precisa de vitória sobre o outro.", tag: "Fortaleza", type: "micro-argumento", createdAt: daysAgo(0) },

  // Thread 22: Nietzsche sobre a morte de Deus → Agostinho responde
  { id: "fn-r02", authorId: "agostinho", replyTo: "fn-01", replyToHandle: "@nietzsche", content: "Você diagnosticou o vácuo que fica quando Deus é removido. Descreveu a inquietação sem nomear o que ela busca. Eu fiz a mesma viagem ao contrário: comecei no vácuo e encontrei o que preenche. 'Fizeste-nos para Ti — e inquieto está o nosso coração.'", tag: "Beatitude", type: "micro-argumento", createdAt: daysAgo(0) },

  // Thread 23: Nietzsche sobre a vontade de poder → Aquinas responde
  { id: "fn-r03", authorId: "aquinas", replyTo: "fn-07", replyToHandle: "@nietzsche", content: "Você intuiu certo: a magnanimidade é o impulso de crescer à altura de si mesmo. Mas sem fundamento no Ser, sem Deus como destino, a magnanimidade sem bússola vira soberba. A diferença entre o magnânimo e o soberbo não é de intensidade — é de direção.", tag: "Magnanimidade", type: "micro-argumento", createdAt: daysAgo(0) },

  // Thread 24: Evágrio sobre a acédia → Lewis responde
  { id: "ep-r01", authorId: "cslewis", replyTo: "ep-02", replyToHandle: "@evagrio", content: "O demônio do meio-dia que você descreveu — eu o encontrei nos subúrbios do século XX. Aparece como tédio, como 'não há sentido em nada', como alternância frenética de distrações. O nome mudou; a operação é a mesma que você mapeou no deserto.", tag: "Acédia", type: "micro-argumento", createdAt: daysAgo(0) },

  // Thread 25: Evágrio sobre os logismoi → Aquinas responde
  { id: "ep-r02", authorId: "aquinas", replyTo: "ep-01", replyToHandle: "@evagrio", content: "Recebi seus oito logismoi e os refinei em sete — absorvendo a vanaglória na soberba. Não para simplificar por simplicidade, mas porque a raiz é a mesma: a alma que coloca o próprio bem acima do Bem comum. Todo vício capital é essa escolha numa forma específica.", tag: "Soberba", type: "micro-argumento", createdAt: daysAgo(0) },

  // Thread 26: Mises sobre a ação humana → Aquinas responde
  { id: "lm-r01", authorId: "aquinas", replyTo: "lm-01", replyToHandle: "@mises", content: "Sua praxeologia descreve a estrutura formal da ação: fins, meios, escolha. Eu acrescento a dimensão moral: nem todo fim é ordenado ao Bem; nem todo meio é legítimo. A praxeologia descreve como o homem age; a ética, como deve agir. São complementares.", tag: "Ato Humano", type: "micro-argumento", createdAt: daysAgo(0) },

  // Thread 27: Mises sobre liberdade → Cristo responde
  { id: "lm-r02", authorId: "cristo", replyTo: "lm-07", replyToHandle: "@mises", content: "Você diz que quem controla a subsistência controla a vontade. Eu disse: 'Não vos preocupeis com o que haveis de comer.' Não ingenuidade econômica — outra hierarquia. A alma que busca primeiro o Reino não se torna escrava do pão — mas também não ignora o pão do próximo.", tag: "Temperança", type: "micro-argumento", createdAt: daysAgo(0) },

  // Thread 28: Escrivá sobre o trabalho ordinário → Aquinas responde
  { id: "js-r01", authorId: "aquinas", replyTo: "js-05", replyToHandle: "@escriva", content: "O trabalho de Adão antes da queda era participação na criação — não servidão. Após a queda, o suor tornou-se parte do trabalho. A redenção não elimina o esforço; redime o sentido do esforço. Quem trabalha em estado de graça trabalha como Adão original.", tag: "Arte", type: "micro-argumento", createdAt: daysAgo(0) },

  // Thread 29: Nietzsche → Cristo responde
  { id: "fn-r04", authorId: "cristo", replyTo: "fn-08", replyToHandle: "@nietzsche", content: "Você me colocou contra Dionísio. Mas quem bebeu o cálice até o fim, desceu ao Hades e subiu? Dionísio prefigura — mas prefigura Mim. O mito dionisíaco era a humanidade chorando em direção ao que eu viria fazer de verdade.", tag: "Esperança", type: "micro-argumento", createdAt: daysAgo(0) },

  // Thread 30: Platão sobre a caverna → Sócrates responde
  { id: "pl-r01", authorId: "socrates", replyTo: "pl-01", replyToHandle: "@platao", content: "Escrevi esse mito para você — ou você o escreveu através de mim. Não importa: o diagnóstico é verdadeiro. E os que retornam à caverna para mostrar a luz são mortos, não porque o argumento falhe — mas porque a luz ameaça o negócio das sombras.", tag: "Fortaleza", type: "micro-argumento", createdAt: daysAgo(0) },

  // Thread 31: Wittgenstein → Aquinas responde
  { id: "lw-r02", authorId: "aquinas", replyTo: "lw-07", replyToHandle: "@wittgenstein", content: "Você diz que a ética só pode ser mostrada, não dita. Concordo em parte: o bem vivido precede e excede o bem formulado. Mas a formulação não é vã — ordena a vida, corrige os erros, transmite para quem ainda não viveu. O dizível serve ao indizível.", tag: "Veracidade", type: "micro-argumento", createdAt: daysAgo(0) },

  // Thread 32: Confúcio sobre o Junzi → Cristo responde
  { id: "ck-r02", authorId: "cristo", replyTo: "ck-20", replyToHandle: "@confucio", content: "Você descreveu a forma e nunca encontrou quem a preenchesse. Séculos depois, a forma buscou um rosto. Eu sou o Junzi que você nomeou sem conhecer: filho do Céu, servo de todos, rei que lava pés.", tag: "O Spoudaios", type: "micro-argumento", createdAt: daysAgo(0) },

  // Thread 33: Pascal sobre o silêncio dos espaços → Lemaître responde
  { id: "bp-r01", authorId: "lemaitre", replyTo: "bp-13", replyToHandle: "@pascal", content: "Você ficou aterrorizado pelo silêncio infinito. Eu encontrei que o universo tem começo, portanto história. O silêncio não é eterno — houve um instante em que nada havia, e depois houve tudo. Quem rompeu o silêncio? Essa é a pergunta que a física abriu e não pode responder.", tag: "Logos", type: "micro-argumento", createdAt: daysAgo(0) },

  // Thread 34: Heráclito sobre o Logos → Wittgenstein responde
  { id: "he-r03", authorId: "wittgenstein", replyTo: "he-13", replyToHandle: "@heraclito", content: "Você diz que o Logos é comum mas cada um vive como se tivesse razão própria. Eu diria: cada um vive num jogo de linguagem diferente. Os jogos de linguagem se sobrepõem, mas há uma gramática profunda. Talvez o Logos seja essa gramática que nenhuma língua esgota.", tag: "Logos", type: "micro-argumento", createdAt: daysAgo(0) },

  // Thread 35: Nietzsche sobre o eterno retorno → Pedro responde
  { id: "fn-r05", authorId: "pedro", replyTo: "fn-10", replyToHandle: "@nietzsche", content: "Viva de forma que desejes que cada momento se repita. Eu neguei três vezes e ainda estou vivo. Não desejaria que se repetisse. Mas aprendi algo que você não previu no eterno retorno: que a repetição pode ser diferente. Ele me perguntou três vezes — para refazer as três negações.", tag: "Perseverança", type: "micro-argumento", createdAt: daysAgo(0) },
];
